#!/usr/bin/env python3
"""Geo Dashboard API — pure stdlib http.server backend (no Flask, no pip).

Run: python3 bin/geo-api.py [--port 8090] [--host 0.0.0.0]

Endpoints:
  GET  /api/places/search  ?q=&lat=&lon=&radius=&type=&limit=
  GET  /api/places/near     ?lat=&lon=&type=&limit=&radius=
  POST /api/places/custom   {name, lat, lon, type, subtype, ...}
  PUT  /api/places/custom/<id>  {name, ...}
  DELETE /api/places/custom/<id>
  GET  /api/places/custom   ?q=&limit=
  POST /api/places/review   {poi_osm_id, custom_poi_id, rating, review_text, ...}
  GET  /api/places/reviews  ?osm_id=&custom_id=
  GET  /api/trails/search   ?q=&type=&limit=
  GET  /api/trails/near     ?lat=&lon=&radius=&type=&limit=
  GET  /api/trails/info/<id>  ?geojson=1
  GET  /api/trails/segments ?minlat=&maxlat=&minlon=&maxlon=&limit=&types=
  GET  /api/transit/stations ?q=
  GET  /api/transit/schedule ?station=&day=
  GET  /api/transit/nearest ?lat=&lon=&limit=
  GET  /api/transit/lines
  GET  /api/transit/bus-stops ?south=&north=&west=&east=&limit=
  GET  /api/geocode         ?q=
  POST /api/location        {lat, lon, accuracy}
  GET  /api/location
  GET  /api/health
"""

# Auth flag — set to True on Hetzner commercial VPS, False here (OVH public instance)
ENABLE_AUTH=True

import argparse
import json
import math
import os
import re
import sqlite3
import sys
import threading
import time
import urllib.request
from datetime import datetime
from difflib import get_close_matches
from http.server import HTTPServer, BaseHTTPRequestHandler
from urllib.parse import urlparse, parse_qs

# Auth module
sys.path.insert(0, os.path.dirname(__file__))
from geo_api_auth import authenticate, create_key, list_keys, revoke_key, get_key_info

# ---------------------------------------------------------------------------
# Paths
# ---------------------------------------------------------------------------
WORKSPACE = os.environ.get("GEO_API_WORKSPACE", os.path.dirname(os.path.dirname(os.path.abspath(__file__))))
DATA_DIR = os.path.join(WORKSPACE, "data")
STATIC_DIR = os.path.join(WORKSPACE, "web", "geo-dashboard")
ROADS_STATIC_DIR = os.path.join(WORKSPACE, "web", "roads")

DB_PATHS = {
    "osm": os.path.join(DATA_DIR, "osm-north-america.db"),
    "trails": os.path.join(DATA_DIR, "trails.db"),
    "transit": os.path.join(DATA_DIR, "translink.db"),
    "custom": os.path.join(DATA_DIR, "custom-places.db"),
    "elevation": os.path.join(DATA_DIR, "elevation.db"),
    "elevation_ukraine": os.path.join(DATA_DIR, "elevation-ukraine.db"),
    "cycling": os.path.join(DATA_DIR, "cycling.db"),
    "addresses": os.path.join(DATA_DIR, "addresses.db"),
}

# Thread-local storage for DB connections
_thread_local = threading.local()

# ---------------------------------------------------------------------------
# Global location state
# ---------------------------------------------------------------------------
_last_location = {"lat": None, "lon": None, "accuracy": None, "timestamp": None}
_location_lock = threading.Lock()

# ---------------------------------------------------------------------------
# Weather cache
# ---------------------------------------------------------------------------
_weather_cache = {}
_weather_cache_lock = threading.Lock()

# ---------------------------------------------------------------------------
# BC Ferries cache
# ---------------------------------------------------------------------------
_ferries_cache = {}
_ferries_cache_lock = threading.Lock()

# ---------------------------------------------------------------------------
# DB helpers
# ---------------------------------------------------------------------------

def get_db(name):
    """Get a SQLite connection for the named database (one per thread)."""
    path = DB_PATHS.get(name)
    if not path or not os.path.exists(path):
        return None
    cache = getattr(_thread_local, "db_cache", None)
    if cache is None:
        cache = {}
        _thread_local.db_cache = cache
    if name not in cache:
        conn = sqlite3.connect(path)
        conn.row_factory = sqlite3.Row
        conn.execute("PRAGMA journal_mode=WAL")
        conn.execute("PRAGMA cache_size=-64000")
        cache[name] = conn
    return cache[name]


def row_to_dict(row):
    if row is None:
        return None
    d = dict(row)
    for k in ("tags",):
        if k in d and isinstance(d[k], str) and d[k].startswith("{"):
            try:
                d[k] = json.loads(d[k])
            except (json.JSONDecodeError, ValueError):
                pass
    return d


def haversine_sql(lat_col, lon_col, lat, lon):
    return (
        f"(12742000.0 * ASIN(SQRT("
        f"POWER(SIN(RADIANS({lat_col} - {lat})/2), 2) + "
        f"COS(RADIANS({lat})) * COS(RADIANS({lat_col})) * "
        f"POWER(SIN(RADIANS({lon_col} - {lon})/2), 2))))"
    )


def bbox_for_radius(lat, lon, radius_m):
    dlat = radius_m / 111320.0
    dlon = radius_m / (111320.0 * math.cos(math.radians(lat)))
    return (lat - dlat, lon - dlon, lat + dlat, lon + dlon)


def haversine(lat1, lon1, lat2, lon2):
    R = 6371000
    p = math.pi / 180
    a = (
        0.5
        - math.cos((lat2 - lat1) * p) / 2
        + math.cos(lat1 * p) * math.cos(lat2 * p) * (1 - math.cos((lon2 - lon1) * p)) / 2
    )
    return 2 * R * math.asin(math.sqrt(a))


def _today_type():
    wd = datetime.now().weekday()
    if wd == 5:
        return "saturday"
    elif wd == 6:
        return "sunday"
    return "weekday"

# Approximate bounding boxes for Canadian provinces/territories
PROVINCE_BOUNDS = {
    "BC": (48.0, 60.0, -139.5, -114.0),
    "AB": (49.0, 60.0, -120.0, -110.0),
    "SK": (49.0, 60.0, -110.0, -101.5),
    "MB": (49.0, 60.0, -102.0, -89.0),
    "ON": (42.0, 57.0, -95.5, -74.0),
    "QC": (45.0, 62.5, -79.5, -57.0),
    "NB": (45.0, 48.0, -69.0, -64.0),
    "NS": (43.5, 47.5, -66.5, -59.5),
    "PE": (46.0, 47.0, -64.5, -61.5),
    "NL": (46.5, 60.5, -67.5, -52.5),
    "YT": (60.0, 72.0, -141.0, -124.0),
    "NT": (60.0, 76.0, -136.0, -102.0),
    "NU": (52.0, 84.0, -121.0, -57.0),
}

_NAME_TO_CODE = {
    "BRITISH COLUMBIA": "BC", "ALBERTA": "AB", "SASKATCHEWAN": "SK",
    "MANITOBA": "MB", "ONTARIO": "ON", "QUEBEC": "QC",
    "NEW BRUNSWICK": "NB", "NOVA SCOTIA": "NS", "PRINCE EDWARD ISLAND": "PE",
    "NEWFOUNDLAND": "NL", "NEWFOUNDLAND AND LABRADOR": "NL",
    "YUKON": "YT", "NORTHWEST TERRITORIES": "NT", "NUNAVUT": "NU",
}

def province_where(lat_col, lon_col, province):
    """Return (sql_fragment, params) for a province bounding box filter, or (None, [])."""
    p = province.upper().strip()
    code = _NAME_TO_CODE.get(p, p)
    if code in PROVINCE_BOUNDS:
        min_lat, max_lat, min_lon, max_lon = PROVINCE_BOUNDS[code]
        return f"({lat_col} BETWEEN ? AND ? AND {lon_col} BETWEEN ? AND ?)", [min_lat, max_lat, min_lon, max_lon]
    return None, []


# ---------------------------------------------------------------------------
# Request handler
# ---------------------------------------------------------------------------

class GeoAPIHandler(BaseHTTPRequestHandler):
    """Pure-stdlib HTTP handler for the Geo API."""

    # Suppress default stderr logging
    def log_message(self, format, *args):
        pass

    # --- CORS helpers ---
    def _send_cors(self):
        self.send_header('Access-Control-Allow-Origin', '*')
        self.send_header('Access-Control-Allow-Headers', 'Content-Type, Authorization, X-API-Key')
        self.send_header('Access-Control-Allow-Methods', 'GET,POST,PUT,DELETE,OPTIONS')

    def _json_response(self, code, data, rate_info=None):
        # Auto-inject rate info from auth if available
        if rate_info is None and hasattr(self, '_rate_info') and self._rate_info:
            rate_info = self._rate_info
        body = json.dumps(data).encode()
        self.send_response(code)
        self.send_header('Content-Type', 'application/json')
        self._send_cors()
        # Rate limit headers
        if rate_info:
            self.send_header('X-RateLimit-Limit', str(rate_info.get('limit', 0)))
            self.send_header('X-RateLimit-Remaining', str(rate_info.get('remaining', 0)))
            self.send_header('X-RateLimit-Reset', str(rate_info.get('reset', 0)))
        self.send_header('Content-Length', str(len(body)))
        self.end_headers()
        self.wfile.write(body)

    def _read_body(self):
        length = int(self.headers.get('Content-Length', 0))
        if length:
            return json.loads(self.rfile.read(length).decode())
        return {}

    # --- Parse path + query ---
    def _parse_request(self):
        parsed = urlparse(self.path)
        path = parsed.path.rstrip('/')
        qs = parse_qs(parsed.query)
        # Flatten single-value params
        params = {k: v[0] if len(v) == 1 else v for k, v in qs.items()}
        return path, params

    # --- OPTIONS (CORS preflight) ---
    def do_OPTIONS(self):
        self.send_response(204)
        self._send_cors()
        self.end_headers()

    # --- Authentication ---
    def _check_auth(self, path):
        """Check API key auth. Returns (allowed, error_response). Stores rate_info on self."""
        _, params = self._parse_request()
        headers = {k: v for k, v in self.headers.items()}
        params['_path'] = path
        params['_method'] = self.command
        allowed, key_data, rate_info, error = authenticate(headers, params)
        self._rate_info = rate_info
        return allowed, error

    # ===================================================================
    # GET
    # ===================================================================
    def do_GET(self):
        path, params = self._parse_request()

        # Public routes (no auth)
        if path == '/api/health':
            return self._health(params)
        if path == '/api/openapi.json':
            return self._serve_openapi()
        if path == '/api/docs':
            return self._serve_redoc()

        # Key management routes (require admin key)
        if path == '/api/keys':
            return self._keys_list(params)
        if path.startswith('/api/keys/'):
            m = re.match(r'^/api/keys/(.+)$', path)
            if m:
                return self._keys_info(m.group(1), params)

        # Static files bypass auth completely
        if not path.startswith('/api/'):
            return self._serve_static(path)

        # All other routes — auth gated by ENABLE_AUTH flag
        if ENABLE_AUTH:
            allowed, error = self._check_auth(path)
            if not allowed:
                status = 429 if error and error.get('error') == 'rate_limited' else 401
                return self._json_response(status, error, self._rate_info)

        # Route matching
        if path == '/api/places/search':
            return self._places_search(params)
        elif path == '/api/places/near':
            return self._places_near(params)
        elif path == '/api/places/custom':
            return self._custom_places_list(params)
        elif path == '/api/trails/search':
            return self._trails_search(params)
        elif path == '/api/trails/near':
            return self._trails_near(params)
        elif path == '/api/trails/segments':
            return self._trails_segments(params)
        elif path == '/api/trails/elevations':
            return self._trails_elevations(params)
        elif path == '/api/transit/stations':
            return self._transit_stations(params)
        elif path == '/api/transit/schedule':
            return self._transit_schedule(params)
        elif path == '/api/transit/nearest':
            return self._transit_nearest(params)
        elif path == '/api/transit/lines':
            return self._transit_lines(params)
        elif path == '/api/transit/bus-stops':
            return self._transit_bus_stops(params)
        elif path == '/api/geocode':
            return self._geocode(params)
        elif path == '/api/location':
            return self._location_get(params)
        elif path == '/api/places/reviews':
            return self._places_reviews_list(params)
        elif path == '/api/elevation':
            return self._elevation(params)
        elif path == '/api/elevation/profile':
            return self._elevation_profile(params)
        elif path == '/api/weather':
            return self._weather(params)
        elif path == '/api/breaking':
            return self._proxy_to_ogs_api('/api/breaking', params)
        elif path == '/api/transit/route':
            return self._transit_route(params)
        elif path == '/api/ferries':
            return self._ferries(params)
        elif path == '/api/sea/pois':
            return self._sea_pois(params)
        elif path == '/api/sea/lighthouses':
            return self._sea_lighthouses(params)
        elif path == '/api/sea/trails':
            return self._sea_trails(params)
        elif path == '/api/cycling/routes':
            return self._cycling_routes(params)
        elif path == '/api/cycling/bbox':
            return self._cycling_bbox(params)
        elif path == '/api/cycling/stats':
            return self._cycling_stats(params)
        elif path == '/api/cycling/municipalities':
            return self._cycling_municipalities()
        elif path == '/api/cycling/paths':
            return self._cycling_paths(params)
        elif path == '/api/cycling/elevation':
            return self._cycling_elevation(params)
        elif path == '/api/mines':
            return self._mines_list(params)
        elif path == '/api/mines/near':
            return self._mines_near(params)
        elif path == '/api/exploration':
            return self._exploration_list(params)
        elif path.startswith('/api/ferries/route/'):
            m = re.match(r'^/api/ferries/route/([^/]+)/schedule$', path)
            if m:
                return self._ferries_route_schedule(m.group(1), params)

        # /api/trails/info/<id>
        m = re.match(r'^/api/trails/info/(\d+)$', path)
        if m:
            return self._trails_info(int(m.group(1)), params)

        # Roads routing endpoint (OSRM)
        if path == '/api/roads/route':
            return self._roads_route(params)

        # Roads events endpoint (DriveBC)
        if path == '/api/roads/events':
            return self._roads_events(params)

        # Fallthrough to 404 for unmatched API routes
        self._json_response(404, {"error": "not found"})

    # ===================================================================
    # POST
    # ===================================================================
    def do_POST(self):
        path, params = self._parse_request()

        # Key management
        if path == '/api/keys':
            return self._keys_create()

        # Auth check — gated by ENABLE_AUTH flag
        if ENABLE_AUTH:
            allowed, error = self._check_auth(path)
            if not allowed:
                status = 429 if error and error.get('error') == 'rate_limited' else 401
                return self._json_response(status, error, self._rate_info)

        if path == '/api/places/custom':
            return self._custom_places_add()
        elif path == '/api/places/review':
            return self._places_review()
        elif path == '/api/location':
            return self._location_update()

        self._json_response(404, {"error": "not found"})

    # ===================================================================
    # PUT
    # ===================================================================
    def do_PUT(self):
        path, params = self._parse_request()

        # Auth check — gated by ENABLE_AUTH flag
        if ENABLE_AUTH:
            allowed, error = self._check_auth(path)
            if not allowed:
                status = 429 if error and error.get('error') == 'rate_limited' else 401
                return self._json_response(status, error, self._rate_info)

        m = re.match(r'^/api/places/custom/(\d+)$', path)
        if m:
            return self._custom_places_update(int(m.group(1)))

        self._json_response(404, {"error": "not found"})

    # ===================================================================
    # DELETE
    # ===================================================================
    def do_DELETE(self):
        path, params = self._parse_request()

        # Key management
        m = re.match(r'^/api/keys/(.+)$', path)
        if m:
            return self._keys_revoke(m.group(1))

        # Auth check — gated by ENABLE_AUTH flag
        if ENABLE_AUTH:
            allowed, error = self._check_auth(path)
            if not allowed:
                status = 429 if error and error.get('error') == 'rate_limited' else 401
                return self._json_response(status, error, self._rate_info)

        m = re.match(r'^/api/places/custom/(\d+)$', path)
        if m:
            return self._custom_places_delete(int(m.group(1)))

        self._json_response(404, {"error": "not found"})

    # ===================================================================
    # KEY MANAGEMENT endpoints (admin only)
    # ===================================================================

    def _keys_list(self, params):
        """GET /api/keys — list all keys (masked). Requires admin key."""
        allowed, error = self._check_auth('/api/keys')
        if not allowed:
            status = 401
            return self._json_response(status, error, self._rate_info)
        keys = list_keys()
        return self._json_response(200, {"keys": keys, "total": len(keys)}, rate_info)

    def _keys_info(self, key, params):
        """GET /api/keys/<key> — get key details. Requires admin key."""
        allowed, error = self._check_auth('/api/keys')
        if not allowed:
            return self._json_response(401, error, self._rate_info)
        info = get_key_info(key)
        if not info:
            return self._json_response(404, {"error": "key not found"})
        # Mask the key
        info['key_masked'] = info['key'][:8] + '...' + info['key'][-4:]
        del info['key']
        return self._json_response(200, info, rate_info)

    def _keys_create(self):
        """POST /api/keys — create a new API key. Requires admin key."""
        allowed, error = self._check_auth('/api/keys')
        if not allowed:
            return self._json_response(401, error, self._rate_info)

        body = self._read_body()
        name = body.get('name', '').strip()
        if not name:
            return self._json_response(400, {"error": "name is required"})

        tier = body.get('tier', 'free')
        if tier not in ('admin', 'pro', 'free'):
            return self._json_response(400, {"error": "tier must be admin, pro, or free"})

        rate_limit = body.get('rate_limit')  # optional override
        metadata = body.get('metadata', {})

        key = create_key(name, tier=tier, rate_limit=rate_limit, metadata=metadata)
        return self._json_response(201, {
            "key": key,
            "name": name,
            "tier": tier,
            "message": "Store this key securely. It will not be shown again."
        }, rate_info)

    def _keys_revoke(self, key):
        """DELETE /api/keys/<key> — revoke an API key. Requires admin key."""
        allowed, error = self._check_auth('/api/keys')
        if not allowed:
            return self._json_response(401, error, self._rate_info)

        if revoke_key(key):
            return self._json_response(200, {"message": "key revoked"}, self._rate_info)
        return self._json_response(404, {"error": "key not found"})

    # ===================================================================
    # PLACES endpoints
    # ===================================================================

    def _places_search(self, p):
        q = p.get("q", "").strip()
        lat = _float(p.get("lat"))
        lon = _float(p.get("lon"))
        radius = _int(p.get("radius"), 5000)
        ptype = p.get("type", "").strip()
        subtype = p.get("subtype", "").strip()
        cuisine = p.get("cuisine", "").strip()
        limit = min(_int(p.get("limit"), 30), 100)

        osm = get_db("osm")
        if osm is None:
            return self._json_response(500, {"error": "OSM database not found"})

        custom = get_db("custom")

        wheres = ["name != ''"]
        params = []
        if q:
            wheres.append("name LIKE ?")
            params.append(f"%{q}%")
        if ptype:
            wheres.append("type = ?")
            params.append(ptype)
        if subtype:
            wheres.append("subtype = ?")
            params.append(subtype)
        if cuisine:
            wheres.append("cuisine LIKE ?")
            params.append(f"%{cuisine}%")

        where = " AND ".join(wheres)

        if lat is not None and lon is not None:
            minlat, minlon, maxlat, maxlon = bbox_for_radius(lat, lon, radius)
            dist = haversine_sql("lat", "lon", lat, lon)
            sql = (
                f"SELECT id, name, type, subtype, cuisine, lat, lon, tags, address, "
                f"ROUND({dist}) AS distance_m, 'osm' AS source "
                f"FROM pois WHERE lat BETWEEN ? AND ? AND lon BETWEEN ? AND ? AND {where} "
                f"ORDER BY distance_m LIMIT ?"
            )
            rows = osm.execute(sql, [minlat, maxlat, minlon, maxlon] + params + [limit]).fetchall()
        else:
            sql = (
                f"SELECT id, name, type, subtype, cuisine, lat, lon, tags, address, "
                f"0 AS distance_m, 'osm' AS source "
                f"FROM pois WHERE {where} ORDER BY name LIMIT ?"
            )
            rows = osm.execute(sql, params + [limit]).fetchall()

        results = [row_to_dict(r) for r in rows]

        # Also search custom POIs
        if custom:
            c_wheres = list(wheres)
            c_params = list(params)
            if lat is not None and lon is not None:
                minlat, minlon, maxlat, maxlon = bbox_for_radius(lat, lon, radius)
                dist = haversine_sql("lat", "lon", lat, lon)
                c_sql = (
                    f"SELECT id, name, type, subtype, cuisine, lat, lon, '' AS tags, address, "
                    f"notes, phone, website, hours, "
                    f"ROUND({dist}) AS distance_m, 'custom' AS source "
                    f"FROM custom_pois WHERE lat BETWEEN ? AND ? AND lon BETWEEN ? AND ? AND {' AND '.join(c_wheres)} "
                    f"ORDER BY distance_m LIMIT ?"
                )
                c_rows = custom.execute(c_sql, [minlat, maxlat, minlon, maxlon] + c_params + [limit]).fetchall()
            else:
                c_sql = (
                    f"SELECT id, name, type, subtype, cuisine, lat, lon, '' AS tags, address, "
                    f"notes, phone, website, hours, "
                    f"0 AS distance_m, 'custom' AS source "
                    f"FROM custom_pois WHERE {' AND '.join(c_wheres)} ORDER BY name LIMIT ?"
                )
                c_rows = custom.execute(c_sql, c_params + [limit]).fetchall()
            results.extend(row_to_dict(r) for r in c_rows)

        if lat is not None and lon is not None:
            results.sort(key=lambda r: r.get("distance_m", 0))

        return self._json_response(200, results[:limit])

    def _places_near(self, p):
        lat = _float(p.get("lat"))
        lon = _float(p.get("lon"))
        if lat is None or lon is None:
            return self._json_response(400, {"error": "lat and lon required"})
        radius = _int(p.get("radius"), 2000)
        ptype = p.get("type", "").strip()
        subtype = p.get("subtype", "").strip()
        limit = min(_int(p.get("limit"), 30), 100)

        osm = get_db("osm")
        if osm is None:
            return self._json_response(500, {"error": "OSM database not found"})

        minlat, minlon, maxlat, maxlon = bbox_for_radius(lat, lon, radius)
        dist = haversine_sql("lat", "lon", lat, lon)

        wheres = ["name != ''", "lat BETWEEN ? AND ?", "lon BETWEEN ? AND ?"]
        params = [minlat, maxlat, minlon, maxlon]
        if ptype:
            wheres.append("type = ?")
            params.append(ptype)
        if subtype:
            wheres.append("subtype = ?")
            params.append(subtype)

        sql = (
            f"SELECT id, name, type, subtype, cuisine, lat, lon, tags, address, "
            f"ROUND({dist}) AS distance_m, 'osm' AS source "
            f"FROM pois WHERE {' AND '.join(wheres)} ORDER BY distance_m LIMIT ?"
        )
        params.append(limit)
        rows = osm.execute(sql, params).fetchall()
        results = [row_to_dict(r) for r in rows]

        custom = get_db("custom")
        if custom:
            c_params = [minlat, maxlat, minlon, maxlon]
            c_wheres = ["lat BETWEEN ? AND ?", "lon BETWEEN ? AND ?"]
            if ptype:
                c_wheres.append("type = ?")
                c_params.append(ptype)
            if subtype:
                c_wheres.append("subtype = ?")
                c_params.append(subtype)
            c_sql = (
                f"SELECT id, name, type, subtype, cuisine, lat, lon, '' AS tags, address, "
                f"notes, phone, website, hours, "
                f"ROUND({dist}) AS distance_m, 'custom' AS source "
                f"FROM custom_pois WHERE {' AND '.join(c_wheres)} ORDER BY distance_m LIMIT ?"
            )
            c_params.append(limit)
            c_rows = custom.execute(c_sql, c_params).fetchall()
            results.extend(row_to_dict(r) for r in c_rows)

        results.sort(key=lambda r: r.get("distance_m", 0))
        return self._json_response(200, results[:limit])

