            return self._json_response(500, {"error": "Custom places DB not found"})
        data = self._read_body()
        fields = []
        params = []
        for col in ("name", "type", "subtype", "cuisine", "address", "phone", "website", "hours", "notes"):
            if col in data:
                fields.append(f"{col} = ?")
                params.append(data[col])
