        if "tags" in data:
            fields.append("tags = ?")
            params.append(json.dumps(data["tags"]) if isinstance(data["tags"], dict) else data["tags"])
        if not fields:
            return self._json_response(400, {"error": "No fields to update"})
        params.append(pid)
        custom.execute(f"UPDATE custom_pois SET {', '.join(fields)} WHERE id = ?", params)
        custom.commit()
        row = custom.execute("SELECT * FROM custom_pois WHERE id = ?", (pid,)).fetchone()
        return self._json_response(200, row_to_dict(row))

