    def _trails_search(self, p):
        trails = get_db("trails")
        if trails is None:
            return self._json_response(500, {"error": "Trails DB not found"})
        q = p.get("q", "").strip()
        ttype = p.get("type", "").strip()
        province = p.get("province", "").strip()
        limit = min(_int(p.get("limit"), 30), 100)

        wheres = []
        params = []
        if q:
            wheres.append("tg.name LIKE ?")
            params.append(f"%{q}%")
        if ttype:
            wheres.append("tg.trail_type = ?")
            params.append(ttype)
        if province:
            psql, pparams = province_where("tg.lat", "tg.lon", province)
            if psql:
                wheres.append(psql)
                params.extend(pparams)
        where = " AND ".join(wheres) if wheres else "1=1"

        sql = (
            f"SELECT tg.id, tg.name, tg.trail_type, tg.sac_scale, tg.surface, "
            f"te.elevation_gain_m, te.elevation_loss_m, te.elevation_min_m, te.elevation_max_m, te.difficulty, "
            f"tg.total_length_km, tg.segment_count, tg.lat, tg.lon "
            f"FROM trail_groups tg LEFT JOIN trail_elevation te ON tg.id = te.trail_group_id WHERE {where} "
            f"ORDER BY tg.total_length_km DESC LIMIT ?"
        )
        params.append(limit)
        rows = trails.execute(sql, params).fetchall()

        if not rows and q:
            t_wheres = ["name LIKE ?"]
            t_params = [f"%{q}%"]
            if ttype:
                t_wheres.append("trail_type = ?")
                t_params.append(ttype)
            sql = (
                f"SELECT id, name, trail_type, sac_scale, surface, length_km, lat, lon "
                f"FROM trails WHERE {' AND '.join(t_wheres)} "
                f"ORDER BY length_km DESC LIMIT ?"
            )
            t_params.append(limit)
            rows = trails.execute(sql, t_params).fetchall()
            return self._json_response(200, [row_to_dict(r) for r in rows])

        return self._json_response(200, [row_to_dict(r) for r in rows])

    def _trails_near(self, p):
        trails = get_db("trails")
        if trails is None:
            return self._json_response(500, {"error": "Trails DB not found"})
        lat = _float(p.get("lat"))
        lon = _float(p.get("lon"))
        if lat is None or lon is None:
            return self._json_response(400, {"error": "lat and lon required"})
        radius = _int(p.get("radius"), 10000)
        ttype = p.get("type", "").strip()
        province = p.get("province", "").strip()
        limit = min(_int(p.get("limit"), 20), 100)

        radius_km = radius / 1000.0
        lat_delta = radius_km / 111.0
        lon_delta = radius_km / (111.0 * math.cos(math.radians(lat)))

        wheres = [
            "tg.min_lat <= ? AND tg.max_lat >= ?",
            "tg.min_lon <= ? AND tg.max_lon >= ?",
        ]
        params = [lat + lat_delta, lat - lat_delta, lon + lon_delta, lon - lat_delta]
        if ttype:
            wheres.append("tg.trail_type = ?")
            params.append(ttype)
        if province:
            psql, pparams = province_where("tg.lat", "tg.lon", province)
            if psql:
                wheres.append(psql)
                params.extend(pparams)

        sql = (
            f"SELECT tg.id, tg.name, tg.trail_type, tg.sac_scale, tg.surface, "
            f"te.elevation_gain_m, te.elevation_loss_m, te.elevation_min_m, te.elevation_max_m, te.difficulty, "
            f"tg.total_length_km, tg.segment_count, tg.lat, tg.lon, "
            f"tg.min_lat, tg.max_lat, tg.min_lon, tg.max_lon "
            f"FROM trail_groups tg LEFT JOIN trail_elevation te ON tg.id = te.trail_group_id WHERE {' AND '.join(wheres)}"
        )
        rows = trails.execute(sql, params).fetchall()

        results = []
        for r in rows:
            d = row_to_dict(r)
            clat = max(d["min_lat"], min(lat, d["max_lat"]))
            clon = max(d["min_lon"], min(lon, d["max_lon"]))
            dist_km = haversine(lat, lon, clat, clon)
            if dist_km <= radius_km:
                d["distance_km"] = round(dist_km, 2)
                results.append(d)

        results.sort(key=lambda x: x["distance_km"])
        results = results[:limit]

        for r in results:
            r.pop("min_lat", None)
            r.pop("max_lat", None)
            r.pop("min_lon", None)
            r.pop("max_lon", None)

        return self._json_response(200, results)

