    def _cycling_routes(self, params):
        """Cycling routes near a lat/lon point."""
        lat = _float(params.get('lat'))
        lon = _float(params.get('lon'))
        radius = _float(params.get('radius', '2')) or 2  # km
        canbics = params.get('class', '').strip()
        muni = params.get('municipality', '').strip()
        limit = min(int(params.get('limit', '100')), 500)

        if lat is None or lon is None:
            return self._json_response(400, {'error': 'lat and lon required'})

        # Approx degree offsets (WGS84, simple cos correction)
        dlat = radius / 111.0
        dlon = radius / (111.0 * math.cos(math.radians(lat)))

        db = self._cycling_db()
        try:
            wheres = [f"lat >= {lat - dlat}", f"lat <= {lat + dlat}",
                     f"lon >= {lon - dlon}", f"lon <= {lon + dlon}"]
            if canbics:
                wheres.append(f"canbics_class = '{canbics}'")
            if muni:
                wheres.append(f"municipality = '{muni}'")
            where = ' AND '.join(wheres)
            cur = db.execute(f'''
                SELECT cs.id, cs.municipality, cs.canbics_class, cs.source_class, cs.surface_type,
                       cs.length_km, cs.geometry_json, cs.elevation_json,
                       ce.elevation_gain_m, ce.elevation_min_m, ce.elevation_max_m, ce.difficulty
                FROM cycling_segments cs
                LEFT JOIN cycling_elevation ce ON cs.id = ce.cycling_segment_id
                WHERE {where} LIMIT {limit}
            ''')
            features = []
            for row in cur:
                geom_json = row[6]
                coords = json.loads(geom_json) if geom_json else None
                if not coords:
                    continue
                props = {
                    'id': row[0],
                    'municipality': row[1],
                    'canbics_class': row[2],
                    'source_class': row[3],
                    'surface_type': row[4],
                    'length_km': row[5],
                    'color': self.CANBICS_COLORS.get(row[2], '#666'),
                }
                # Point-level elevation from enrichment
                elev_json = row[7]
                if elev_json:
                    try:
                        elev_data = json.loads(elev_json)
                        stats = elev_data.get('stats', {})
                        props['elevation_gain_m'] = stats.get('gain_m')
                        props['elevation_loss_m'] = stats.get('loss_m')
                        props['elevation_min_m'] = stats.get('min_m')
                        props['elevation_max_m'] = stats.get('max_m')
                    except (json.JSONDecodeError, TypeError):
                        pass
                # Fall back to aggregate elevation table
                if 'elevation_gain_m' not in props and row[8] is not None:
                    props['elevation_gain_m'] = row[8]
                    props['elevation_min_m'] = row[9]
                    props['elevation_max_m'] = row[10]
                    props['difficulty'] = row[11]
                features.append({
                    'type': 'Feature',
                    'geometry': {'type': 'MultiLineString', 'coordinates': coords},
                    'properties': props,
                })
            self._json_response(200, {'type': 'FeatureCollection', 'features': features})
        finally:
            db.close()

    def _cycling_bbox(self, params):
        """Cycling routes in a bounding box. Pass mode=routes for merged paths."""
        mode = params.get('mode', 'segments')
        if mode == 'routes':
            return self._cycling_paths(params)
        south = _float(params.get('south'))
        north = _float(params.get('north'))
        west = _float(params.get('west'))
        east = _float(params.get('east'))
        canbics = params.get('class', '').strip()
        muni = params.get('municipality', '').strip()
        limit = min(int(params.get('limit', '500')), 2000)

        if any(v is None for v in [south, north, west, east]):
            return self._json_response(400, {'error': 'south, north, west, east required'})

        db = self._cycling_db()
        try:
            # Direct WGS84 overlap query — no Lambert conversion needed
            wheres = [f"max_lat >= {south}", f"min_lat <= {north}",
                     f"max_lon >= {west}", f"min_lon <= {east}"]
            if canbics:
                wheres.append(f"canbics_class = '{canbics}'")
            if muni:
                wheres.append(f"municipality = '{muni}'")
            where = ' AND '.join(wheres)
            cur = db.execute(f'''
                SELECT cs.id, cs.municipality, cs.canbics_class, cs.source_class, cs.surface_type,
                       cs.length_km, cs.geometry_json, cs.elevation_json,
                       ce.elevation_gain_m, ce.elevation_min_m, ce.elevation_max_m, ce.difficulty
                FROM cycling_segments cs
                LEFT JOIN cycling_elevation ce ON cs.id = ce.cycling_segment_id
                WHERE {where} LIMIT {limit}
            ''')
            features = []
            for row in cur:
                geom_json = row[6]
                coords = json.loads(geom_json) if geom_json else None
                if not coords:
                    continue
                props = {
                    'id': row[0],
                    'municipality': row[1],
                    'canbics_class': row[2],
                    'source_class': row[3],
                    'surface_type': row[4],
                    'length_km': row[5],
                    'color': self.CANBICS_COLORS.get(row[2], '#666'),
                }
                # Point-level elevation from enrichment
                elev_json = row[7]
                if elev_json:
                    try:
                        elev_data = json.loads(elev_json)
                        stats = elev_data.get('stats', {})
                        props['elevation_gain_m'] = stats.get('gain_m')
                        props['elevation_loss_m'] = stats.get('loss_m')
                        props['elevation_min_m'] = stats.get('min_m')
                        props['elevation_max_m'] = stats.get('max_m')
                    except (json.JSONDecodeError, TypeError):
                        pass
                # Fall back to aggregate elevation table
                if 'elevation_gain_m' not in props and row[8] is not None:
                    props['elevation_gain_m'] = row[8]
                    props['elevation_min_m'] = row[9]
                    props['elevation_max_m'] = row[10]
                    props['difficulty'] = row[11]
                features.append({
                    'type': 'Feature',
                    'geometry': {'type': 'MultiLineString', 'coordinates': coords},
                    'properties': props,
                })
            self._json_response(200, {'type': 'FeatureCollection', 'features': features})
        finally:
            db.close()

    def _cycling_paths(self, params):
        """Merged cycling paths (cross-class routes)."""
        south = _float(params.get('south'))
        north = _float(params.get('north'))
        west = _float(params.get('west'))
        east = _float(params.get('east'))
        muni = params.get('municipality', '').strip()
        limit = min(int(params.get('limit', '500')), 2000)

        if any(v is None for v in [south, north, west, east]):
            return self._json_response(400, {'error': 'south, north, west, east required'})

        db = self._cycling_db()
        try:
            where_parts = [
                f"max_lat >= {south}",
                f"min_lat <= {north}",
                f"max_lon >= {west}",
                f"min_lon <= {east}",
            ]
            if muni:
                safe_muni = muni.replace("'", "''")
                where_parts.append(f"municipality = '{safe_muni}'")
            where = ' AND '.join(where_parts)
            cur = db.execute(f'''
                SELECT id, segment_count, total_length_km, total_points,
                       dominant_class, class_composition, class_sequence,
                       municipality, geometry_json
                FROM cycling_paths
                WHERE {where} LIMIT {limit}
            ''')
            features = []
            for row in cur:
                geom = json.loads(row[8])
                comp = json.loads(row[5]) if row[5] else {}
                seq = json.loads(row[6]) if row[6] else []
                features.append({
                    'type': 'Feature',
                    'geometry': geom,
                    'properties': {
                        'path_id': row[0],
                        'segment_count': row[1],
                        'total_length_km': row[2],
                        'total_points': row[3],
                        'dominant_class': row[4],
                        'class_composition': comp,
                        'class_sequence': seq,
                        'municipality': row[7],
                        'mode': 'routes',
                    },
                })
            self._json_response(200, {
                'type': 'FeatureCollection',
                'features': features,
                'mode': 'routes',
            })
        finally:
            db.close()

    def _cycling_elevation(self, params):
        """Return elevation profile for a specific cycling segment."""
        seg_id = params.get('id', '').strip()
        if not seg_id:
            return self._json_response(400, {'error': 'id required'})
        db = self._cycling_db()
        try:
            cur = db.execute(
                'SELECT elevation_json FROM cycling_segments WHERE id = ?', (seg_id,))
            row = cur.fetchone()
            if not row or not row[0]:
                return self._json_response(404, {'error': 'No elevation data for segment'})
            return self._json_response(200, json.loads(row[0]))
        finally:
            db.close()

    def _cycling_stats(self, params):
        """Cycling infrastructure stats."""
        db = self._cycling_db()
        try:
            cur = db.execute('''
                SELECT municipality, canbics_class, COUNT(*), ROUND(COALESCE(SUM(length_km),0),1)
                FROM cycling_segments
                GROUP BY municipality, canbics_class ORDER BY municipality, canbics_class
            ''')
            municipalities = {}
            for row in cur:
                muni = row[0]
                if muni not in municipalities:
                    municipalities[muni] = {'classes': {}, 'total_km': 0, 'total_segments': 0}
                municipalities[muni]['classes'][row[1]] = {'segments': row[2], 'km': row[3]}
                municipalities[muni]['total_km'] += row[3]
                municipalities[muni]['total_segments'] += row[2]
            self._json_response(200, {'municipalities': municipalities})
        finally:
            db.close()

    def _cycling_municipalities(self):
        """List available municipalities."""
        db = self._cycling_db()
        try:
            cur = db.execute('''
                SELECT municipality, COUNT(*), ROUND(COALESCE(SUM(length_km),0),1)
                FROM cycling_segments
                GROUP BY municipality ORDER BY SUM(length_km) DESC
            ''')
            result = [{'name': r[0], 'segments': r[1], 'km': r[2]} for r in cur]
            self._json_response(200, {'municipalities': result})
        finally:
            db.close()

    def _mines_list(self, params):
        """List all mines with optional filters."""
        province = params.get('province', '').strip()
        product = params.get('product', '').strip()
        group = params.get('group', '').strip()
        limit = min(int(params.get('limit', '500')), 1000)

        db = sqlite3.connect(DB_PATHS["osm"])
        try:
            wheres, vals = [], []
            if province:
                wheres.append("province LIKE ?")
                vals.append(f"%{province}%")
            if product:
                wheres.append("product LIKE ?")
                vals.append(f"%{product}%")
            if group:
                wheres.append("operation_group LIKE ?")
                vals.append(f"%{group}%")
            where = " AND ".join(wheres) if wheres else "1=1"
            cur = db.execute(f"SELECT * FROM mines WHERE {where} LIMIT {limit}", vals)
            cols = [d[0] for d in cur.description]
            features = []
            for row in cur:
                props = dict(zip(cols, row))
                lat, lon = props.pop('latitude', None), props.pop('longitude', None)
                if lat and lon:
                    features.append({'type': 'Feature',
                        'geometry': {'type': 'Point', 'coordinates': [lon, lat]},
                        'properties': props})
            self._json_response(200, {'type': 'FeatureCollection', 'features': features,
                'count': len(features)})
        finally:
            db.close()

    def _mines_near(self, params):
        """Mines near a lat/lon point."""
        lat = _float(params.get('lat'))
        lon = _float(params.get('lon'))
        radius = _float(params.get('radius', '100')) or 100  # km
        limit = min(int(params.get('limit', '50')), 200)

        if lat is None or lon is None:
            return self._json_response(400, {'error': 'lat and lon required'})

        dlat = radius / 111.0
        dlon = radius / (111.0 * math.cos(math.radians(lat)))

        db = sqlite3.connect(DB_PATHS["osm"])
        try:
            cur = db.execute(f'''
                SELECT * FROM mines
                WHERE latitude BETWEEN ? AND ? AND longitude BETWEEN ? AND ?
                LIMIT {limit}
            ''', (lat - dlat, lat + dlat, lon - dlon, lon + dlon))
            cols = [d[0] for d in cur.description]
            features = []
            for row in cur:
                props = dict(zip(cols, row))
                mlat, mlon = props.pop('latitude', None), props.pop('longitude', None)
                if mlat and mlon:
                    dist = math.sqrt(((mlat - lat) * 111) ** 2 + ((mlon - lon) * 111 * math.cos(math.radians(lat))) ** 2)
                    props['distance_km'] = round(dist, 1)
                    features.append({'type': 'Feature',
                        'geometry': {'type': 'Point', 'coordinates': [mlon, mlat]},
                        'properties': props})
            features.sort(key=lambda f: f['properties']['distance_km'])
            self._json_response(200, {'type': 'FeatureCollection', 'features': features,
                'count': len(features)})
        finally:
            db.close()

    def _exploration_list(self, params):
        """List exploration projects with optional filters."""
        province = params.get('province', '').strip()
        commodity = params.get('commodity', '').strip()
        limit = min(int(params.get('limit', '500')), 1000)

        db = sqlite3.connect(DB_PATHS["osm"])
        try:
            wheres, vals = [], []
            if province:
                wheres.append("province LIKE ?")
                vals.append(f"%{province}%")
            if commodity:
                wheres.append("commodity_group LIKE ?")
                vals.append(f"%{commodity}%")
            where = " AND ".join(wheres) if wheres else "1=1"
            cur = db.execute(f"SELECT * FROM exploration_projects WHERE {where} LIMIT {limit}", vals)
            cols = [d[0] for d in cur.description]
            features = []
            for row in cur:
                props = dict(zip(cols, row))
                lat, lon = props.pop('latitude', None), props.pop('longitude', None)
                if lat and lon:
                    features.append({'type': 'Feature',
                        'geometry': {'type': 'Point', 'coordinates': [lon, lat]},
                        'properties': props})
            self._json_response(200, {'type': 'FeatureCollection', 'features': features,
                'count': len(features)})
        finally:
            db.close()

    def _transit_route(self, p):
        """Transit routing endpoint — calls bin/transit-route."""
        origin = p.get("from", "").strip()
        dest = p.get("to", "").strip()
        depart = p.get("depart", "").strip()

        if not origin or not dest:
            return self._json_response(400, {"error": "Missing 'from' and/or 'to' parameters"})

        import subprocess
        cmd = [os.path.join(WORKSPACE, "bin", "transit-route"),
               "--from", origin, "--to", dest, "--json"]
        if depart:
            cmd.extend(["--depart", depart])

        try:
            result = subprocess.run(cmd, capture_output=True, text=True, timeout=30,
                                    cwd=WORKSPACE)
            if result.returncode != 0:
                err = result.stderr.strip().split(chr(10))[-1] if result.stderr else "No routes found"
                return self._json_response(404, {"error": err})
            data = json.loads(result.stdout)
            return self._json_response(200, data)
        except subprocess.TimeoutExpired:
            return self._json_response(504, {"error": "Route query timed out"})
        except json.JSONDecodeError:
            return self._json_response(500, {"error": "Invalid route output"})


# ---------------------------------------------------------------------------
# Param parsing helpers
# ---------------------------------------------------------------------------

def _lambert_inv(easting, northing):
    """Inverse Lambert Conformal Conic (EPSG:3347 Stats Canada Lambert) -> WGS84."""
    import math
    a = 6378137.0
    f = 1 / 298.257222101
    e2 = 2 * f - f * f
    sqrt_e = math.sqrt(e2)
    lat1 = math.radians(49); lat2 = math.radians(77)
    lat0 = math.radians(63.390675); lon0 = math.radians(-91.866386)
    x0 = 6200000.0; y0 = 3000000.0

    def _t(lat):
        sl = math.sin(lat)
        return math.sqrt((1 - sl) / (1 + sl)) * ((1 + sqrt_e * sl) / (1 - sqrt_e * sl)) ** (sqrt_e / 2)

    def _m(lat):
        sl = math.sin(lat)
        return math.cos(lat) / math.sqrt(1 - e2 * sl * sl)

    m1, m2 = _m(lat1), _m(lat2)
    t1, t2, t0 = _t(lat1), _t(lat2), _t(lat0)
    n = (math.log(m1) - math.log(m2)) / (math.log(t1) - math.log(t2))
    F = m1 / (n * t1 ** n)
    rho0 = a * F * t0 ** n

    x, y = easting - x0, northing - y0
    rho = math.copysign(math.sqrt(x * x + (rho0 - y) ** 2), n)
    theta = math.atan2(x, rho0 - y)
    t = (rho / (a * F)) ** (1 / n)
    lon = theta / n + lon0

    lat = math.pi / 2 - 2 * math.atan(t)
    for _ in range(15):
        sl = math.sin(lat)
        lat = math.pi / 2 - 2 * math.atan(t * ((1 - sqrt_e * sl) / (1 + sqrt_e * sl)) ** (sqrt_e / 2))
    return math.degrees(lat), math.degrees(lon)


def _lambert_fwd(lat_deg, lon_deg):
    """Forward WGS84 -> Lambert Conformal Conic (EPSG:3347)."""
    import math
    a = 6378137.0
    f = 1 / 298.257222101
    e2 = 2 * f - f * f
    sqrt_e = math.sqrt(e2)
    lat1 = math.radians(49); lat2 = math.radians(77)
    lat0 = math.radians(63.390675); lon0 = math.radians(-91.866386)
    x0 = 6200000.0; y0 = 3000000.0

    def _t(lat):
        sl = math.sin(lat)
        return math.sqrt((1 - sl) / (1 + sl)) * ((1 + sqrt_e * sl) / (1 - sqrt_e * sl)) ** (sqrt_e / 2)

    def _m(lat):
        sl = math.sin(lat)
        return math.cos(lat) / math.sqrt(1 - e2 * sl * sl)

    m1, m2 = _m(lat1), _m(lat2)
    t1, t2, t0 = _t(lat1), _t(lat2), _t(lat0)
    n = (math.log(m1) - math.log(m2)) / (math.log(t1) - math.log(t2))
    F = m1 / (n * t1 ** n)
    rho0 = a * F * t0 ** n

    lat = math.radians(lat_deg); lon = math.radians(lon_deg)
    t = _t(lat)
    rho = a * F * t ** n
    theta = n * (lon - lon0)
    easting = x0 + rho * math.sin(theta)
    northing = y0 + rho0 - rho * math.cos(theta)
    return easting, northing


def _float(v):
    if v is None:
        return None
    try:
        return float(v)
    except (ValueError, TypeError):
        return None


def _int(v, default=None):
    if v is None:
        return default
    try:
        return int(v)
    except (ValueError, TypeError):
        return default


# ---------------------------------------------------------------------------
# Threaded HTTP server
# ---------------------------------------------------------------------------

class ThreadedHTTPServer(HTTPServer):
    """Handle each request in a new thread."""
    daemon_threads = True
    allow_reuse_address = True

    def process_request(self, request, client_address):
        t = threading.Thread(target=self._handle, args=(request, client_address))
        t.daemon = True
        t.start()

    def _handle(self, request, client_address):
        try:
            self.finish_request(request, client_address)
        except Exception:
            self.handle_error(request, client_address)
        finally:
            self.shutdown_request(request)


# ---------------------------------------------------------------------------

# ---------------------------------------------------------------------------
if __name__ == "__main__":
    parser = argparse.ArgumentParser(description="Geo Dashboard API")
    parser.add_argument("--host", default="0.0.0.0")
    parser.add_argument("--port", type=int, default=8090)
    args = parser.parse_args()
    print(f"Geo API starting on http://{args.host}:{args.port}")
    print(f"Databases: {DATA_DIR}")
    for k, v in DB_PATHS.items():
        print(f"  {k}: {'OK' if os.path.exists(v) else 'MISSING'} ({v})")
    server = ThreadedHTTPServer((args.host, args.port), GeoAPIHandler)
    # Handle SIGTERM for clean quadlet shutdown
    import signal
    def _handle_signal(signum, frame):
        print(f"\nReceived signal {signum}, shutting down.")
        server.shutdown()
    signal.signal(signal.SIGTERM, _handle_signal)
    try:
        server.serve_forever()
    except KeyboardInterrupt:
        print("\nShutting down.")
        server.shutdown()

