_NAME_TO_CODE = {
    "BRITISH COLUMBIA": "BC", "ALBERTA": "AB", "SASKATCHEWAN": "SK",
    "MANITOBA": "MB", "ONTARIO": "ON", "QUEBEC": "QC",
    "NEW BRUNSWICK": "NB", "NOVA SCOTIA": "NS", "PRINCE EDWARD ISLAND": "PE",
    "NEWFOUNDLAND": "NL", "NEWFOUNDLAND AND LABRADOR": "NL",
    "YUKON": "YT", "NORTHWEST TERRITORIES": "NT", "NUNAVUT": "NU",
}

def province_where(lat_col, lon_col, province):
    """Return (sql_fragment, params) for a province bounding box filter, or (None, [])."""
    p = province.upper().strip()
    code = _NAME_TO_CODE.get(p, p)
    if code in PROVINCE_BOUNDS:
        min_lat, max_lat, min_lon, max_lon = PROVINCE_BOUNDS[code]
        return f"({lat_col} BETWEEN ? AND ? AND {lon_col} BETWEEN ? AND ?)", [min_lat, max_lat, min_lon, max_lon]
    return None, []


# ---------------------------------------------------------------------------
# Request handler
# ---------------------------------------------------------------------------

class GeoAPIHandler(BaseHTTPRequestHandler):
    """Pure-stdlib HTTP handler for the Geo API."""

    # Suppress default stderr logging
    def log_message(self, format, *args):
        pass

    # --- CORS helpers ---
    def _send_cors(self):
        self.send_header('Access-Control-Allow-Origin', '*')
        self.send_header('Access-Control-Allow-Headers', 'Content-Type, Authorization, X-API-Key')
        self.send_header('Access-Control-Allow-Methods', 'GET,POST,PUT,DELETE,OPTIONS')

    def _json_response(self, code, data, rate_info=None):
        # Auto-inject rate info from auth if available
        if rate_info is None and hasattr(self, '_rate_info') and self._rate_info:
            rate_info = self._rate_info
        body = json.dumps(data).encode()
        self.send_response(code)
        self.send_header('Content-Type', 'application/json')
        self._send_cors()
        # Rate limit headers
        if rate_info:
            self.send_header('X-RateLimit-Limit', str(rate_info.get('limit', 0)))
            self.send_header('X-RateLimit-Remaining', str(rate_info.get('remaining', 0)))
            self.send_header('X-RateLimit-Reset', str(rate_info.get('reset', 0)))
        self.send_header('Content-Length', str(len(body)))
        self.end_headers()
        self.wfile.write(body)

    def _read_body(self):
        length = int(self.headers.get('Content-Length', 0))
        if length:
            return json.loads(self.rfile.read(length).decode())
        return {}

    # --- Parse path + query ---
    def _parse_request(self):
        parsed = urlparse(self.path)
        path = parsed.path.rstrip('/')
        qs = parse_qs(parsed.query)
        # Flatten single-value params
        params = {k: v[0] if len(v) == 1 else v for k, v in qs.items()}
        return path, params

    # --- OPTIONS (CORS preflight) ---
    def do_OPTIONS(self):
        self.send_response(204)
        self._send_cors()
        self.end_headers()

    # --- Authentication ---
    def _check_auth(self, path):
        """Check API key auth. Returns (allowed, error_response). Stores rate_info on self."""
        _, params = self._parse_request()
        headers = {k: v for k, v in self.headers.items()}
        params['_path'] = path
        params['_method'] = self.command
        allowed, key_data, rate_info, error = authenticate(headers, params)
        self._rate_info = rate_info
        return allowed, error

    # ===================================================================
    # GET
    # ===================================================================
    def do_GET(self):
        path, params = self._parse_request()

        # Public routes (no auth)
        if path == '/api/health':
            return self._health(params)
        if path == '/api/openapi.json':
            return self._serve_openapi()
        if path == '/api/docs':
            return self._serve_redoc()

        # Key management routes (require admin key)
        if path == '/api/keys':
            return self._keys_list(params)
        if path.startswith('/api/keys/'):
            m = re.match(r'^/api/keys/(.+)$', path)
            if m:
                return self._keys_info(m.group(1), params)

        # Static files bypass auth completely
        if not path.startswith('/api/'):
            return self._serve_static(path)

        # All other routes — auth gated by ENABLE_AUTH flag
        if ENABLE_AUTH:
            allowed, error = self._check_auth(path)
            if not allowed:
                status = 429 if error and error.get('error') == 'rate_limited' else 401
                return self._json_response(status, error, self._rate_info)

        # Route matching
        if path == '/api/places/search':
            return self._places_search(params)
        elif path == '/api/places/near':
            return self._places_near(params)
        elif path == '/api/places/custom':
            return self._custom_places_list(params)
        elif path == '/api/trails/search':
            return self._trails_search(params)
        elif path == '/api/trails/near':
            return self._trails_near(params)
        elif path == '/api/trails/segments':
            return self._trails_segments(params)
        elif path == '/api/trails/elevations':
            return self._trails_elevations(params)
        elif path == '/api/transit/stations':
            return self._transit_stations(params)
        elif path == '/api/transit/schedule':
            return self._transit_schedule(params)
        elif path == '/api/transit/nearest':
            return self._transit_nearest(params)
        elif path == '/api/transit/lines':
            return self._transit_lines(params)
        elif path == '/api/transit/bus-stops':
            return self._transit_bus_stops(params)
        elif path == '/api/geocode':
            return self._geocode(params)
        elif path == '/api/location':
            return self._location_get(params)
        elif path == '/api/places/reviews':
            return self._places_reviews_list(params)
        elif path == '/api/elevation':
            return self._elevation(params)
        elif path == '/api/elevation/profile':
            return self._elevation_profile(params)
        elif path == '/api/weather':
            return self._weather(params)
        elif path == '/api/breaking':
            return self._proxy_to_ogs_api('/api/breaking', params)
        elif path == '/api/transit/route':
            return self._transit_route(params)
        elif path == '/api/ferries':
            return self._ferries(params)
        elif path == '/api/sea/pois':
            return self._sea_pois(params)
        elif path == '/api/sea/lighthouses':
            return self._sea_lighthouses(params)
        elif path == '/api/sea/trails':
            return self._sea_trails(params)
        elif path == '/api/cycling/routes':
            return self._cycling_routes(params)
        elif path == '/api/cycling/bbox':
            return self._cycling_bbox(params)
        elif path == '/api/cycling/stats':
            return self._cycling_stats(params)
        elif path == '/api/cycling/municipalities':
            return self._cycling_municipalities()
        elif path == '/api/cycling/paths':
            return self._cycling_paths(params)
        elif path == '/api/cycling/elevation':
            return self._cycling_elevation(params)
        elif path == '/api/mines':
            return self._mines_list(params)
        elif path == '/api/mines/near':
            return self._mines_near(params)
        elif path == '/api/exploration':
            return self._exploration_list(params)
        elif path.startswith('/api/ferries/route/'):
            m = re.match(r'^/api/ferries/route/([^/]+)/schedule$', path)
            if m:
                return self._ferries_route_schedule(m.group(1), params)

        # /api/trails/info/<id>
        m = re.match(r'^/api/trails/info/(\d+)$', path)
        if m:
            return self._trails_info(int(m.group(1)), params)

        # Roads routing endpoint (OSRM)
        if path == '/api/roads/route':
            return self._roads_route(params)

        # Roads events endpoint (DriveBC)
        if path == '/api/roads/events':
            return self._roads_events(params)

        # Fallthrough to 404 for unmatched API routes
        self._json_response(404, {"error": "not found"})

    # ===================================================================
    # POST
    # ===================================================================
    def do_POST(self):
        path, params = self._parse_request()

        # Key management
        if path == '/api/keys':
            return self._keys_create()

        # Auth check — gated by ENABLE_AUTH flag
        if ENABLE_AUTH:
            allowed, error = self._check_auth(path)
            if not allowed:
                status = 429 if error and error.get('error') == 'rate_limited' else 401
                return self._json_response(status, error, self._rate_info)

        if path == '/api/places/custom':
            return self._custom_places_add()
        elif path == '/api/places/review':
            return self._places_review()
        elif path == '/api/location':
            return self._location_update()

        self._json_response(404, {"error": "not found"})

    # ===================================================================
    # PUT
    # ===================================================================
    def do_PUT(self):
        path, params = self._parse_request()

        # Auth check — gated by ENABLE_AUTH flag
        if ENABLE_AUTH:
            allowed, error = self._check_auth(path)
            if not allowed:
                status = 429 if error and error.get('error') == 'rate_limited' else 401
                return self._json_response(status, error, self._rate_info)

        m = re.match(r'^/api/places/custom/(\d+)$', path)
        if m:
            return self._custom_places_update(int(m.group(1)))

        self._json_response(404, {"error": "not found"})

    # ===================================================================
    # DELETE
    # ===================================================================
    def do_DELETE(self):
        path, params = self._parse_request()

        # Key management
        m = re.match(r'^/api/keys/(.+)$', path)
        if m:
            return self._keys_revoke(m.group(1))

        # Auth check — gated by ENABLE_AUTH flag
        if ENABLE_AUTH:
            allowed, error = self._check_auth(path)
            if not allowed:
                status = 429 if error and error.get('error') == 'rate_limited' else 401
                return self._json_response(status, error, self._rate_info)

        m = re.match(r'^/api/places/custom/(\d+)$', path)
        if m:
            return self._custom_places_delete(int(m.group(1)))

        self._json_response(404, {"error": "not found"})

    # ===================================================================
    # KEY MANAGEMENT endpoints (admin only)
    # ===================================================================

    def _keys_list(self, params):
        """GET /api/keys — list all keys (masked). Requires admin key."""
        allowed, error = self._check_auth('/api/keys')
        if not allowed:
            status = 401
            return self._json_response(status, error, self._rate_info)
        keys = list_keys()
        return self._json_response(200, {"keys": keys, "total": len(keys)}, rate_info)

    def _keys_info(self, key, params):
        """GET /api/keys/<key> — get key details. Requires admin key."""
        allowed, error = self._check_auth('/api/keys')
        if not allowed:
            return self._json_response(401, error, self._rate_info)
        info = get_key_info(key)
        if not info:
            return self._json_response(404, {"error": "key not found"})
        # Mask the key
        info['key_masked'] = info['key'][:8] + '...' + info['key'][-4:]
        del info['key']
        return self._json_response(200, info, rate_info)

    def _keys_create(self):
        """POST /api/keys — create a new API key. Requires admin key."""
        allowed, error = self._check_auth('/api/keys')
        if not allowed:
            return self._json_response(401, error, self._rate_info)

        body = self._read_body()
        name = body.get('name', '').strip()
        if not name:
            return self._json_response(400, {"error": "name is required"})

        tier = body.get('tier', 'free')
        if tier not in ('admin', 'pro', 'free'):
            return self._json_response(400, {"error": "tier must be admin, pro, or free"})

        rate_limit = body.get('rate_limit')  # optional override
        metadata = body.get('metadata', {})

        key = create_key(name, tier=tier, rate_limit=rate_limit, metadata=metadata)
        return self._json_response(201, {
            "key": key,
            "name": name,
            "tier": tier,
            "message": "Store this key securely. It will not be shown again."
        }, rate_info)

    def _keys_revoke(self, key):
        """DELETE /api/keys/<key> — revoke an API key. Requires admin key."""
        allowed, error = self._check_auth('/api/keys')
        if not allowed:
            return self._json_response(401, error, self._rate_info)

        if revoke_key(key):
            return self._json_response(200, {"message": "key revoked"}, self._rate_info)
        return self._json_response(404, {"error": "key not found"})

