    # ===================================================================

    def _places_search(self, p):
        q = p.get("q", "").strip()
        lat = _float(p.get("lat"))
        lon = _float(p.get("lon"))
        radius = _int(p.get("radius"), 5000)
        ptype = p.get("type", "").strip()
        subtype = p.get("subtype", "").strip()
        cuisine = p.get("cuisine", "").strip()
        limit = min(_int(p.get("limit"), 30), 100)

        osm = get_db("osm")
        if osm is None:
            return self._json_response(500, {"error": "OSM database not found"})

        custom = get_db("custom")

        wheres = ["name != ''"]
        params = []
        if q:
            wheres.append("name LIKE ?")
            params.append(f"%{q}%")
        if ptype:
            wheres.append("type = ?")
            params.append(ptype)
        if subtype:
            wheres.append("subtype = ?")
            params.append(subtype)
        if cuisine:
            wheres.append("cuisine LIKE ?")
            params.append(f"%{cuisine}%")

        where = " AND ".join(wheres)

        if lat is not None and lon is not None:
            minlat, minlon, maxlat, maxlon = bbox_for_radius(lat, lon, radius)
            dist = haversine_sql("lat", "lon", lat, lon)
            sql = (
                f"SELECT id, name, type, subtype, cuisine, lat, lon, tags, address, "
                f"ROUND({dist}) AS distance_m, 'osm' AS source "
                f"FROM pois WHERE lat BETWEEN ? AND ? AND lon BETWEEN ? AND ? AND {where} "
                f"ORDER BY distance_m LIMIT ?"
            )
            rows = osm.execute(sql, [minlat, maxlat, minlon, maxlon] + params + [limit]).fetchall()
        else:
            sql = (
                f"SELECT id, name, type, subtype, cuisine, lat, lon, tags, address, "
                f"0 AS distance_m, 'osm' AS source "
                f"FROM pois WHERE {where} ORDER BY name LIMIT ?"
            )
            rows = osm.execute(sql, params + [limit]).fetchall()

        results = [row_to_dict(r) for r in rows]

        # Also search custom POIs
        if custom:
            c_wheres = list(wheres)
            c_params = list(params)
            if lat is not None and lon is not None:
                minlat, minlon, maxlat, maxlon = bbox_for_radius(lat, lon, radius)
                dist = haversine_sql("lat", "lon", lat, lon)
                c_sql = (
                    f"SELECT id, name, type, subtype, cuisine, lat, lon, '' AS tags, address, "
                    f"notes, phone, website, hours, "
                    f"ROUND({dist}) AS distance_m, 'custom' AS source "
                    f"FROM custom_pois WHERE lat BETWEEN ? AND ? AND lon BETWEEN ? AND ? AND {' AND '.join(c_wheres)} "
                    f"ORDER BY distance_m LIMIT ?"
                )
                c_rows = custom.execute(c_sql, [minlat, maxlat, minlon, maxlon] + c_params + [limit]).fetchall()
            else:
                c_sql = (
                    f"SELECT id, name, type, subtype, cuisine, lat, lon, '' AS tags, address, "
                    f"notes, phone, website, hours, "
                    f"0 AS distance_m, 'custom' AS source "
                    f"FROM custom_pois WHERE {' AND '.join(c_wheres)} ORDER BY name LIMIT ?"
                )
                c_rows = custom.execute(c_sql, c_params + [limit]).fetchall()
            results.extend(row_to_dict(r) for r in c_rows)

        if lat is not None and lon is not None:
            results.sort(key=lambda r: r.get("distance_m", 0))

        return self._json_response(200, results[:limit])

    def _places_near(self, p):
        lat = _float(p.get("lat"))
        lon = _float(p.get("lon"))
        if lat is None or lon is None:
            return self._json_response(400, {"error": "lat and lon required"})
        radius = _int(p.get("radius"), 2000)
        ptype = p.get("type", "").strip()
        subtype = p.get("subtype", "").strip()
        limit = min(_int(p.get("limit"), 30), 100)

        osm = get_db("osm")
        if osm is None:
            return self._json_response(500, {"error": "OSM database not found"})

        minlat, minlon, maxlat, maxlon = bbox_for_radius(lat, lon, radius)
        dist = haversine_sql("lat", "lon", lat, lon)

        wheres = ["name != ''", "lat BETWEEN ? AND ?", "lon BETWEEN ? AND ?"]
        params = [minlat, maxlat, minlon, maxlon]
        if ptype:
            wheres.append("type = ?")
            params.append(ptype)
        if subtype:
            wheres.append("subtype = ?")
            params.append(subtype)

        sql = (
            f"SELECT id, name, type, subtype, cuisine, lat, lon, tags, address, "
            f"ROUND({dist}) AS distance_m, 'osm' AS source "
            f"FROM pois WHERE {' AND '.join(wheres)} ORDER BY distance_m LIMIT ?"
        )
        params.append(limit)
        rows = osm.execute(sql, params).fetchall()
        results = [row_to_dict(r) for r in rows]

        custom = get_db("custom")
        if custom:
            c_params = [minlat, maxlat, minlon, maxlon]
            c_wheres = ["lat BETWEEN ? AND ?", "lon BETWEEN ? AND ?"]
            if ptype:
                c_wheres.append("type = ?")
                c_params.append(ptype)
            if subtype:
                c_wheres.append("subtype = ?")
                c_params.append(subtype)
            c_sql = (
                f"SELECT id, name, type, subtype, cuisine, lat, lon, '' AS tags, address, "
                f"notes, phone, website, hours, "
                f"ROUND({dist}) AS distance_m, 'custom' AS source "
                f"FROM custom_pois WHERE {' AND '.join(c_wheres)} ORDER BY distance_m LIMIT ?"
            )
            c_params.append(limit)
            c_rows = custom.execute(c_sql, c_params).fetchall()
            results.extend(row_to_dict(r) for r in c_rows)

        results.sort(key=lambda r: r.get("distance_m", 0))
        return self._json_response(200, results[:limit])

