    def _custom_places_list(self, p):
        custom = get_db("custom")
        if custom is None:
            return self._json_response(500, {"error": "Custom places DB not found"})
        q = p.get("q", "").strip()
        subtype = p.get("subtype", "").strip()
        limit = min(_int(p.get("limit"), 100), 500)
        if q and subtype:
            rows = custom.execute(
                "SELECT * FROM custom_pois WHERE name LIKE ? AND subtype = ? ORDER BY added_at DESC LIMIT ?",
                (f"%{q}%", subtype, limit),
            ).fetchall()
        elif q:
            rows = custom.execute(
                "SELECT * FROM custom_pois WHERE name LIKE ? ORDER BY added_at DESC LIMIT ?",
                (f"%{q}%", limit),
            ).fetchall()
        elif subtype:
            rows = custom.execute(
                "SELECT * FROM custom_pois WHERE subtype = ? ORDER BY added_at DESC LIMIT ?",
                (subtype, limit),
            ).fetchall()
        else:
            rows = custom.execute(
                "SELECT * FROM custom_pois ORDER BY added_at DESC LIMIT ?", (limit,)
            ).fetchall()
        return self._json_response(200, [row_to_dict(r) for r in rows])

    def _custom_places_add(self):
        custom = get_db("custom")
        if custom is None:
            return self._json_response(500, {"error": "Custom places DB not found"})
        data = self._read_body()
        name = data.get("name", "").strip()
        lat = data.get("lat")
        lon = data.get("lon")
        if not name or lat is None or lon is None:
            return self._json_response(400, {"error": "name, lat, lon are required"})
        try:
            cur = custom.execute(
                """INSERT INTO custom_pois (name, type, subtype, cuisine, lat, lon, address, phone, website, hours, notes, tags, source)
                   VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'user')""",
                (
                    name, data.get("type"), data.get("subtype"), data.get("cuisine"),
                    float(lat), float(lon),
                    data.get("address"), data.get("phone"), data.get("website"),
                    data.get("hours"), data.get("notes"),
                    json.dumps(data["tags"]) if isinstance(data.get("tags"), dict) else data.get("tags"),
                ),
            )
            custom.commit()
            new_id = cur.lastrowid
            row = custom.execute("SELECT * FROM custom_pois WHERE id = ?", (new_id,)).fetchone()
            return self._json_response(201, row_to_dict(row))
        except Exception as e:
            return self._json_response(500, {"error": str(e)})

    def _custom_places_update(self, pid):
        custom = get_db("custom")
        if custom is None:
            return self._json_response(500, {"error": "Custom places DB not found"})
        data = self._read_body()
        fields = []
        params = []
        for col in ("name", "type", "subtype", "cuisine", "address", "phone", "website", "hours", "notes"):
            if col in data:
                fields.append(f"{col} = ?")
                params.append(data[col])
        if "lat" in data:
            fields.append("lat = ?")
            params.append(float(data["lat"]))
        if "lon" in data:
            fields.append("lon = ?")
            params.append(float(data["lon"]))
        if "tags" in data:
            fields.append("tags = ?")
            params.append(json.dumps(data["tags"]) if isinstance(data["tags"], dict) else data["tags"])
        if not fields:
            return self._json_response(400, {"error": "No fields to update"})
        params.append(pid)
        custom.execute(f"UPDATE custom_pois SET {', '.join(fields)} WHERE id = ?", params)
        custom.commit()
        row = custom.execute("SELECT * FROM custom_pois WHERE id = ?", (pid,)).fetchone()
        return self._json_response(200, row_to_dict(row))

    def _custom_places_delete(self, pid):
        custom = get_db("custom")
        if custom is None:
            return self._json_response(500, {"error": "Custom places DB not found"})
