    def _trails_info(self, trail_id, p):
        trails = get_db("trails")
        if trails is None:
            return self._json_response(500, {"error": "Trails DB not found"})
        want_geojson = p.get("geojson", "0") == "1"

        row = trails.execute("SELECT * FROM trail_groups WHERE id = ?", (trail_id,)).fetchone()
        if row:
            result = row_to_dict(row)
            # Elevation enrichment
            elev = trails.execute(
                "SELECT elevation_gain_m, elevation_loss_m, elevation_min_m, elevation_max_m, elevation_avg_m, difficulty, samples_count FROM trail_elevation WHERE trail_group_id = ?",
                (trail_id,)
            ).fetchone()
            if elev:
                result["elevation_gain_m"] = elev[0]
                result["elevation_loss_m"] = elev[1]
                result["elevation_min_m"] = elev[2]
                result["elevation_max_m"] = elev[3]
                result["elevation_avg_m"] = elev[4]
                result["difficulty"] = elev[5]
                result["elevation_samples"] = elev[6]
            segs = trails.execute(
                "SELECT id, name, trail_type, sac_scale, surface, length_km FROM trails WHERE name = (SELECT name FROM trail_groups WHERE id = ?) ORDER BY length_km DESC",
                (trail_id,),
            ).fetchall()
            result["segments"] = [row_to_dict(s) for s in segs]
            if want_geojson:
                seg_ids = [s["id"] for s in result["segments"]]
                if seg_ids:
                    placeholders = ",".join("?" * len(seg_ids))
                    pts = trails.execute(
                        f"SELECT trail_id, lat, lon, seq FROM trail_points "
                        f"WHERE trail_id IN ({placeholders}) ORDER BY trail_id, seq",
                        seg_ids,
                    ).fetchall()
                    features = []
                    current_tid = None
                    coords = []
                    for pt in pts:
                        if pt["trail_id"] != current_tid:
                            if coords and current_tid is not None:
                                features.append({
                                    "type": "Feature",
                                    "properties": {"trail_id": current_tid},
                                    "geometry": {"type": "LineString", "coordinates": coords},
                                })
                            current_tid = pt["trail_id"]
                            coords = []
                        coords.append([pt["lon"], pt["lat"]])
                    if coords and current_tid is not None:
                        features.append({
                            "type": "Feature",
                            "properties": {"trail_id": current_tid},
                            "geometry": {"type": "LineString", "coordinates": coords},
                        })
                    result["geojson"] = {"type": "FeatureCollection", "features": features}
            return self._json_response(200, result)

        row = trails.execute("SELECT * FROM trails WHERE id = ?", (trail_id,)).fetchone()
        if row is None:
            return self._json_response(404, {"error": "Trail not found"})
        result = row_to_dict(row)
        if want_geojson:
            pts = trails.execute(
                "SELECT lat, lon, seq FROM trail_points WHERE trail_id = ? ORDER BY seq",
                (trail_id,),
            ).fetchall()
            coords = [[pt["lon"], pt["lat"]] for pt in pts]
            result["geojson"] = {
                "type": "Feature",
                "properties": {"id": trail_id, "name": result["name"]},
                "geometry": {"type": "LineString", "coordinates": coords},
            }
        return self._json_response(200, result)

