    def _geocode(self, p):
        """Search places, POIs, transit stations, bus stops, and addresses."""
        osm = get_db("osm")
        translink = get_db("transit")
        addr_db = get_db("addresses")
        q = p.get("q", "").strip()
        if not q:
            return self._json_response(400, {"error": "q required"})

        results = []
        seen = set()

        def add_result(d, result_type):
            key = (d.get("name", "").lower(), round(d.get("lat", 0), 4), round(d.get("lon", 0), 4))
            if key not in seen:
                seen.add(key)
                d["result_type"] = result_type
                results.append(d)

        q_upper = q.upper()
        q_lower = q.lower()

        # -- 1. OSM places (cities, towns, villages) --
        if osm:
            row = osm.execute(
                """SELECT name, lat, lon, place_type FROM places WHERE LOWER(name) = LOWER(?)
                   ORDER BY
                     CASE WHEN lat BETWEEN 48.0 AND 60.0 AND lon BETWEEN -140.0 AND -114.0 THEN 0 ELSE 1 END,
                     CASE WHEN lat BETWEEN 42.0 AND 84.0 AND lon BETWEEN -141.0 AND -52.0 THEN 0 ELSE 1 END,
                     CASE place_type WHEN 'city' THEN 0 WHEN 'town' THEN 1 WHEN 'village' THEN 2
                          WHEN 'suburb' THEN 3 WHEN 'neighbourhood' THEN 4 WHEN 'hamlet' THEN 5 ELSE 6 END
                   LIMIT 1""",
                (q,),
            ).fetchall()
            if not row:
                row = osm.execute(
                    """SELECT name, lat, lon, place_type FROM places WHERE LOWER(name) LIKE ?
                       ORDER BY
                         CASE WHEN lat BETWEEN 48.0 AND 60.0 AND lon BETWEEN -140.0 AND -114.0 THEN 0 ELSE 1 END,
                         CASE place_type WHEN 'city' THEN 0 WHEN 'town' THEN 1 WHEN 'village' THEN 2 ELSE 3 END,
                         LENGTH(name)
                       LIMIT 1""",
                    (q_lower + "%",),
                ).fetchall()
            if not row:
                row = osm.execute(
                    """SELECT name, lat, lon, place_type FROM places WHERE LOWER(name) LIKE ?
                       ORDER BY
                         CASE WHEN lat BETWEEN 48.0 AND 60.0 AND lon BETWEEN -140.0 AND -114.0 THEN 0 ELSE 1 END,
                         LENGTH(name)
                       LIMIT 1""",
                    ("%" + q_lower + "%",),
                ).fetchall()
            for r in row:
                add_result(row_to_dict(r), "place")

        # -- 2. OSM POIs (restaurants, parks, hospitals, shops) --
        if osm and len(results) < 10:
            poi_rows = osm.execute(
                """SELECT name, lat, lon, type, subtype, address
                   FROM pois
                   WHERE LOWER(name) = LOWER(?)
                     AND lat BETWEEN 48.0 AND 60.0 AND lon BETWEEN -140.0 AND -114.0
                   ORDER BY LENGTH(name)
                   LIMIT 1""",
                (q,),
            ).fetchall()
            if not poi_rows:
                poi_rows = osm.execute(
                    """SELECT name, lat, lon, type, subtype, address
                       FROM pois
                       WHERE LOWER(name) LIKE ?
                         AND lat BETWEEN 48.0 AND 60.0 AND lon BETWEEN -140.0 AND -114.0
                       ORDER BY LENGTH(name)
                       LIMIT 1""",
                    (q_lower + "%",),
                ).fetchall()
            if not poi_rows:
                poi_rows = osm.execute(
                    """SELECT name, lat, lon, type, subtype, address
                       FROM pois
                       WHERE LOWER(name) LIKE ?
                         AND lat BETWEEN 48.0 AND 60.0 AND lon BETWEEN -140.0 AND -114.0
                       ORDER BY LENGTH(name)
                       LIMIT 1""",
                    ("%" + q_lower + "%",),
                ).fetchall()
            for r in poi_rows:
                d = row_to_dict(r)
                poi_type = d.get("subtype") or d.get("type") or ""
                if poi_type and poi_type not in ("yes", "no"):
                    d["poi_type"] = poi_type
                add_result(d, "poi")

        # -- 3. Transit stations (SkyTrain/SeaBus) --
        if translink and len(results) < 10:
            stn_rows = translink.execute(
                """SELECT DISTINCT
                     REPLACE(REPLACE(REPLACE(stop_name, ' @ Platform 1', ''),
                                      ' @ Platform 2', ''),
                             ' @ Platform 3', '') as name,
                     lat, lon,
                     GROUP_CONCAT(DISTINCT l.route_name) as lines
                   FROM stations s
                   LEFT JOIN station_lines sl ON s.stop_id = sl.stop_id
                   LEFT JOIN lines l ON sl.route_id = l.route_id
                   WHERE s.stop_name LIKE ?
                   GROUP BY name, lat, lon
                   ORDER BY LENGTH(name), name
                   LIMIT 1""",
                ("%" + q_upper + "%",),
            ).fetchall()
            for r in stn_rows:
                d = row_to_dict(r)
                d["place_type"] = "station"
                add_result(d, "station")

        # -- 4. Bus stops --
        if translink and len(results) < 10:
            bus_rows = translink.execute(
                """SELECT stop_name AS name, stop_lat AS lat, stop_lon AS lon
                   FROM bus_stops
                   WHERE stop_name LIKE ?
                   ORDER BY LENGTH(stop_name)
                   LIMIT 1""",
                ("%" + q_upper + "%",),
            ).fetchall()
            for r in bus_rows:
                d = row_to_dict(r)
                d["place_type"] = "bus_stop"
                add_result(d, "bus_stop")

        # -- 7. Addresses --
        if addr_db and len(results) < 10:
            max_addr = min(4, 10 - len(results))
            addr_rows = addr_db.execute(
                """SELECT lat, lon,
                     CASE WHEN street_no IS NOT NULL AND street_no != ''
                       THEN street_no || ' ' || street_name || ' ' || COALESCE(street_type,'')
                       ELSE full_addr
                     END AS display_name,
                     city, postal_code, 'address' AS place_type
                   FROM addresses
                   WHERE province = 'BC' AND street_name LIKE ?
                   ORDER BY LENGTH(full_addr)
                   LIMIT ?""",
                (q_upper + "%", max_addr),
            ).fetchall()
            if not addr_rows:
                addr_rows = addr_db.execute(
                    """SELECT lat, lon,
                        CASE WHEN street_no IS NOT NULL AND street_no != ''
                          THEN street_no || ' ' || street_name || ' ' || COALESCE(street_type,'')
                          ELSE full_addr
                        END AS display_name,
                        city, postal_code, 'address' AS place_type
                       FROM addresses
                       WHERE province = 'BC' AND street_name LIKE ?
                       ORDER BY LENGTH(full_addr)
                       LIMIT ?""",
                    ("%" + q_upper + "%", max_addr),
                ).fetchall()
            if not addr_rows:
                addr_rows = addr_db.execute(
                    """SELECT lat, lon, full_addr AS display_name,
                       city, postal_code, 'address' AS place_type
                       FROM addresses
                       WHERE province = 'BC' AND full_addr LIKE ?
                       ORDER BY LENGTH(full_addr)
                       LIMIT ?""",
                    ("%" + q_upper + "%", max_addr),
                ).fetchall()
            for r in addr_rows:
                d = row_to_dict(r)
                d["name"] = d.get("display_name", d.get("name", ""))
                add_result(d, "address")


        return self._json_response(200, results)

    def _trails_segments(self, p):
        """Return raw trail segments (including unnamed) for a bounding box."""
        trails = get_db("trails")
        if trails is None:
            return self._json_response(500, {"error": "Trails DB not found"})
        minlat = _float(p.get("minlat"))
        maxlat = _float(p.get("maxlat"))
        minlon = _float(p.get("minlon"))
        maxlon = _float(p.get("maxlon"))
        if None in (minlat, maxlat, minlon, maxlon):
            return self._json_response(400, {"error": "minlat, maxlat, minlon, maxlon required"})
        limit = min(_int(p.get("limit"), 5000), 25000)
        types_str = p.get("types", "").strip()

        wheres = ["lat BETWEEN ? AND ?", "lon BETWEEN ? AND ?"]
        params = [minlat, maxlat, minlon, maxlon]
        if types_str:
            types = [t.strip() for t in types_str.split(",") if t.strip()]
            if types:
                wheres.append(f"trail_type IN ({','.join('?' * len(types))})")
                params.extend(types)

        sql = (f"SELECT id, name, trail_type, sac_scale, surface, length_km, elevation_gain, lat, lon, geometry "
               f"FROM trails WHERE {' AND '.join(wheres)} LIMIT ?")
        params.append(limit)
        rows = trails.execute(sql, params).fetchall()
        return self._json_response(200, [row_to_dict(r) for r in rows])

    def _trails_elevations(self, p):
        """Return elevation enrichment data for trail groups in a bounding box."""
        trails = get_db("trails")
        if trails is None:
            return self._json_response(500, {"error": "Trails DB not found"})
        minlat = _float(p.get("minlat"))
        maxlat = _float(p.get("maxlat"))
        minlon = _float(p.get("minlon"))
        maxlon = _float(p.get("maxlon"))
        if None in (minlat, maxlat, minlon, maxlon):
            return self._json_response(400, {"error": "minlat, maxlat, minlon, maxlon required"})

        rows = trails.execute("""
            SELECT tg.name, te.elevation_gain_m, te.elevation_min_m, te.elevation_max_m,
                   te.elevation_avg_m, te.difficulty
            FROM trail_groups tg
            JOIN trail_elevation te ON tg.id = te.trail_group_id
            WHERE tg.min_lat <= ? AND tg.max_lat >= ?
              AND tg.min_lon <= ? AND tg.max_lon >= ?
        """, (maxlat, minlat, maxlon, minlon)).fetchall()

        results = {}
        for r in rows:
            name = r[0]
            if name not in results:
                results[name] = {
                    "gain": r[1], "min": r[2], "max": r[3],
                    "avg": r[4], "difficulty": r[5]
                }
        return self._json_response(200, results)

    def _trails_info(self, trail_id, p):
        trails = get_db("trails")
        if trails is None:
            return self._json_response(500, {"error": "Trails DB not found"})
        want_geojson = p.get("geojson", "0") == "1"

        row = trails.execute("SELECT * FROM trail_groups WHERE id = ?", (trail_id,)).fetchone()
        if row:
            result = row_to_dict(row)
            # Elevation enrichment
            elev = trails.execute(
                "SELECT elevation_gain_m, elevation_loss_m, elevation_min_m, elevation_max_m, elevation_avg_m, difficulty, samples_count FROM trail_elevation WHERE trail_group_id = ?",
                (trail_id,)
            ).fetchone()
            if elev:
                result["elevation_gain_m"] = elev[0]
                result["elevation_loss_m"] = elev[1]
                result["elevation_min_m"] = elev[2]
                result["elevation_max_m"] = elev[3]
                result["elevation_avg_m"] = elev[4]
                result["difficulty"] = elev[5]
                result["elevation_samples"] = elev[6]
            segs = trails.execute(
                "SELECT id, name, trail_type, sac_scale, surface, length_km FROM trails WHERE name = (SELECT name FROM trail_groups WHERE id = ?) ORDER BY length_km DESC",
                (trail_id,),
            ).fetchall()
            result["segments"] = [row_to_dict(s) for s in segs]
            if want_geojson:
                seg_ids = [s["id"] for s in result["segments"]]
                if seg_ids:
                    placeholders = ",".join("?" * len(seg_ids))
                    pts = trails.execute(
                        f"SELECT trail_id, lat, lon, seq FROM trail_points "
                        f"WHERE trail_id IN ({placeholders}) ORDER BY trail_id, seq",
                        seg_ids,
                    ).fetchall()
                    features = []
                    current_tid = None
                    coords = []
                    for pt in pts:
                        if pt["trail_id"] != current_tid:
                            if coords and current_tid is not None:
                                features.append({
                                    "type": "Feature",
                                    "properties": {"trail_id": current_tid},
                                    "geometry": {"type": "LineString", "coordinates": coords},
                                })
                            current_tid = pt["trail_id"]
                            coords = []
                        coords.append([pt["lon"], pt["lat"]])
                    if coords and current_tid is not None:
                        features.append({
                            "type": "Feature",
                            "properties": {"trail_id": current_tid},
                            "geometry": {"type": "LineString", "coordinates": coords},
                        })
                    result["geojson"] = {"type": "FeatureCollection", "features": features}
            return self._json_response(200, result)

        row = trails.execute("SELECT * FROM trails WHERE id = ?", (trail_id,)).fetchone()
        if row is None:
            return self._json_response(404, {"error": "Trail not found"})
        result = row_to_dict(row)
        if want_geojson:
            pts = trails.execute(
                "SELECT lat, lon, seq FROM trail_points WHERE trail_id = ? ORDER BY seq",
                (trail_id,),
            ).fetchall()
            coords = [[pt["lon"], pt["lat"]] for pt in pts]
            result["geojson"] = {
                "type": "Feature",
                "properties": {"id": trail_id, "name": result["name"]},
                "geometry": {"type": "LineString", "coordinates": coords},
            }
        return self._json_response(200, result)

