    @staticmethod
    def _normalize_name(name):
        """Normalize stop name for fuzzy matching."""
        return re.sub(r'[^a-z0-9 ]', '', name.lower()).strip()

    def _transit_stations(self, p):
        transit = get_db("transit")
        if transit is None:
            return self._json_response(500, {"error": "Transit DB not found"})
        q = p.get("q", "").strip()
        groups = {}

        # --- SkyTrain stations ---
        if q:
            # Try multiple query variants for normalization
            for variant in (q, q.replace('-', ' ')):
                rows = transit.execute(
                    "SELECT stop_id, stop_name, lat, lon FROM stations WHERE stop_name LIKE ?",
                    (f"%{variant}%",),
                ).fetchall()
                for r in rows:
                    d = row_to_dict(r)
                    base = d["stop_name"].split(" @ ")[0]
                    for sfx in (" Northbound", " Southbound", " Eastbound", " Westbound"):
                        if base.endswith(sfx):
                            base = base[: -len(sfx)]
                            break
                    if base not in groups:
                        groups[base] = {"name": base, "lat": d["lat"], "lon": d["lon"], "stop_ids": [], "lines": []}
                    groups[base]["stop_ids"].append(d["stop_id"])
        else:
            rows = transit.execute("SELECT stop_id, stop_name, lat, lon FROM stations").fetchall()
            for r in rows:
                d = row_to_dict(r)
                base = d["stop_name"].split(" @ ")[0]
                for sfx in (" Northbound", " Southbound", " Eastbound", " Westbound"):
                    if base.endswith(sfx):
                        base = base[: -len(sfx)]
                        break
                if base not in groups:
                    groups[base] = {"name": base, "lat": d["lat"], "lon": d["lon"], "stop_ids": [], "lines": []}
                groups[base]["stop_ids"].append(d["stop_id"])

        for base, info in list(groups.items()):
            if info["stop_ids"]:
                ph = ",".join("?" * len(info["stop_ids"]))
                lines = transit.execute(
                    f"SELECT DISTINCT l.route_id, l.route_name FROM station_lines sl "
                    f"JOIN lines l ON sl.route_id = l.route_id WHERE sl.stop_id IN ({ph})",
                    info["stop_ids"],
                ).fetchall()
                info["lines"] = [{"route_id": l["route_id"], "route_name": l["route_name"]} for l in lines]
            del info["stop_ids"]

        # --- Bus stops (search if query provided) ---
        # Uses pre-computed bus_stop_routes cache for fast lookups
        if q and len(q) >= 2:
            for variant in (q, q.replace('-', ' ')):
                bus_rows = transit.execute(
                    "SELECT bs.stop_id, bs.stop_name, bs.stop_lat, bs.stop_lon, "
                    "GROUP_CONCAT(DISTINCT bsr.route_short_name) AS routes "
                    "FROM bus_stops bs "
                    "JOIN bus_stop_routes bsr ON bs.stop_id = bsr.stop_id "
                    "WHERE bs.stop_name LIKE ? "
                    "GROUP BY bs.stop_id "
                    "LIMIT 50",
                    (f"%{variant}%",),
                ).fetchall()

                bus_groups = {}
                for r in bus_rows:
                    d = row_to_dict(r)
                    raw_name = d["stop_name"]
                    base = raw_name.split(" @ ")[0] if " @ " in raw_name and "Bay" in raw_name else raw_name
                    for sfx in (" Northbound", " Southbound", " Eastbound", " Westbound"):
                        if base.endswith(sfx):
                            base = base[: -len(sfx)]
                            break
                    if base not in bus_groups:
                        bus_groups[base] = {
                            "name": base,
                            "lat": d["stop_lat"],
                            "lon": d["stop_lon"],
                            "lines": [],
                        }
                    if d.get("routes"):
                        for rn in d["routes"].split(","):
                            rn = rn.strip()
                            existing_ids = {l["route_id"] for l in bus_groups[base]["lines"]}
                            rid = f"bus:{rn}"
                            if rid not in existing_ids:
                                bus_groups[base]["lines"].append({"route_id": rid, "route_name": f"Bus {rn}"})

                for base, info in bus_groups.items():
                    if base not in groups:
                        groups[base] = info
                    else:
                        existing = {l["route_id"] for l in groups[base]["lines"]}
                        for line in info["lines"]:
                            if line["route_id"] not in existing:
                                groups[base]["lines"].append(line)

        # --- Fuzzy fallback ---
        if q and len(q) >= 2 and not groups:
            q_norm = self._normalize_name(q)
            # Collect all stop names
            all_stops = {}
            for row in transit.execute("SELECT stop_id, stop_name, lat, lon FROM stations").fetchall():
                d = row_to_dict(row)
                base = d["stop_name"].split(" @ ")[0]
                n = self._normalize_name(base)
                if n not in all_stops:
                    all_stops[n] = {"name": base, "lat": d["lat"], "lon": d["lon"]}
            for row in transit.execute("SELECT stop_id, stop_name, stop_lat, stop_lon FROM bus_stops WHERE location_type IN (0,1)").fetchall():
                d = row_to_dict(row)
                n = self._normalize_name(d["stop_name"])
                if n not in all_stops:
                    all_stops[n] = {"name": d["stop_name"], "lat": d["stop_lat"], "lon": d["stop_lon"]}

            matches = get_close_matches(q_norm, all_stops.keys(), n=15, cutoff=0.5)
            for m in matches:
                info = all_stops[m]
                groups[info["name"]] = {"name": info["name"], "lat": info["lat"], "lon": info["lon"], "lines": []}

        # --- Geocode/POI fallback: if no stops found, search local OSM data ---
        if q and len(q) >= 3 and not groups:
            osm = get_db("osm")
            if osm is not None:
                # Search POIs (landmarks, buildings, restaurants, etc.)
                poi_rows = osm.execute(
                    "SELECT name, lat, lon, type FROM pois "
                    "WHERE name LIKE ? AND lat > 1.0 AND lat BETWEEN 49.0 AND 49.5 AND lon BETWEEN -123.5 AND -122.0 "
                    "LIMIT 10",
                    (f"%{q}%",),
                ).fetchall()
                for r in poi_rows:
                    d = row_to_dict(r)
                    if d["name"] not in groups:
                        groups[d["name"]] = {
                            "name": d["name"],
                            "lat": d["lat"],
                            "lon": d["lon"],
                            "lines": [],
                            "type": "address",
                        }

                # Search places (neighborhoods, towns)
                if not groups:
                    place_rows = osm.execute(
                        "SELECT name, lat, lon, place_type FROM places "
                        "WHERE name LIKE ? AND lat > 1.0 AND lat BETWEEN 49.0 AND 49.5 AND lon BETWEEN -123.5 AND -122.0 "
                        "LIMIT 10",
                        (f"%{q}%",),
                    ).fetchall()
                    for r in place_rows:
                        d = row_to_dict(r)
                        if d["name"] not in groups:
                            groups[d["name"]] = {
                                "name": d["name"],
                                "lat": d["lat"],
                                "lon": d["lon"],
                                "lines": [],
                                "type": "address",
                            }

        return self._json_response(200, list(groups.values()))

    def _transit_schedule(self, p):
        transit = get_db("transit")
        if transit is None:
            return self._json_response(500, {"error": "Transit DB not found"})
        station = p.get("station", "").strip()
        day = p.get("day", "").strip() or _today_type()
        if not station:
            return self._json_response(400, {"error": "station required"})

        rows = transit.execute(
            "SELECT stop_id, stop_name FROM stations WHERE stop_name LIKE ?",
            (f"%{station}%",),
        ).fetchall()
        if not rows:
            return self._json_response(404, {"error": f"No station matching '{station}'"})

        groups = {}
        for r in rows:
            base = r["stop_name"].split(" @ ")[0]
            for sfx in (" Northbound", " Southbound", " Eastbound", " Westbound"):
                if base.endswith(sfx):
                    base = base[: -len(sfx)]
                    break
            groups.setdefault(base, []).append(r["stop_id"])

        result = {}
        for base, stop_ids in groups.items():
            ph = ",".join("?" * len(stop_ids))
            lines = transit.execute(
                f"SELECT DISTINCT l.route_id, l.route_name FROM station_lines sl "
                f"JOIN lines l ON sl.route_id = l.route_id WHERE sl.stop_id IN ({ph})",
                stop_ids,
            ).fetchall()

            schedules = []
            for line in lines:
                freqs = transit.execute(
                    f"SELECT period, headway_min, first_departure, last_departure "
                    f"FROM frequencies WHERE route_id = ? AND stop_id IN ({ph}) AND day_type = ? "
                    f"ORDER BY first_departure",
                    [line["route_id"]] + stop_ids + [day],
                ).fetchall()

                seen = {}
                for f in freqs:
                    if f["period"] not in seen:
                        seen[f["period"]] = {
                            "period": f["period"],
                            "headway_min": round(f["headway_min"], 1),
                            "first": f["first_departure"],
                            "last": f["last_departure"],
                        }
                schedules.append({
                    "line": line["route_name"],
                    "frequencies": list(seen.values()),
                })
            result[base] = schedules

        result["_day"] = day
        return self._json_response(200, result)

    def _transit_nearest(self, p):
        transit = get_db("transit")
        if transit is None:
            return self._json_response(500, {"error": "Transit DB not found"})
        lat = _float(p.get("lat"))
        lon = _float(p.get("lon"))
        if lat is None or lon is None:
            return self._json_response(400, {"error": "lat and lon required"})
        limit = min(_int(p.get("limit"), 5), 20)

        rows = transit.execute("SELECT stop_id, stop_name, lat, lon FROM stations").fetchall()
        distances = []
        for r in rows:
            d = haversine(lat, lon, r["lat"], r["lon"])
            distances.append((d, r))

        distances.sort(key=lambda x: x[0])

        seen = set()
        results = []
        for dist, r in distances:
            base = r["stop_name"].split(" @ ")[0]
            for sfx in (" Northbound", " Southbound", " Eastbound", " Westbound"):
                if base.endswith(sfx):
                    base = base[: -len(sfx)]
                    break
            if base in seen:
                continue
            seen.add(base)

            lines = transit.execute(
                "SELECT DISTINCT l.route_name FROM station_lines sl "
                "JOIN lines l ON sl.route_id = l.route_id WHERE sl.stop_id = ?",
                (r["stop_id"],),
            ).fetchall()
            results.append({
                "name": base,
                "lat": r["lat"],
                "lon": r["lon"],
                "distance_m": round(dist),
                "lines": [l["route_name"] for l in lines],
            })
            if len(results) >= limit:
                break

        return self._json_response(200, results)

    def _transit_lines(self, p):
        transit = get_db("transit")
        if transit is None:
            return self._json_response(500, {"error": "Transit DB not found"})
        rows = transit.execute(
            "SELECT l.route_id, l.route_name, l.route_type, COUNT(DISTINCT sl.stop_id) AS stop_count "
            "FROM lines l JOIN station_lines sl ON l.route_id = sl.route_id "
            "GROUP BY l.route_id ORDER BY l.route_name"
        ).fetchall()
        return self._json_response(200, [row_to_dict(r) for r in rows])

    def _transit_bus_stops(self, p):
        """Return bus stops within a bounding box (for map overlay when zoomed in)."""
        transit = get_db("transit")
        if transit is None:
            return self._json_response(500, {"error": "Transit DB not found"})
        south = _float(p.get("south"))
        north = _float(p.get("north"))
        west = _float(p.get("west"))
        east = _float(p.get("east"))
        if None in (south, north, west, east):
            return self._json_response(400, {"error": "south, north, west, east required"})

        limit = min(_int(p.get("limit"), 200), 500)

        rows = transit.execute(
            "SELECT bs.stop_id, bs.stop_name, bs.stop_lat, bs.stop_lon, "
            "GROUP_CONCAT(DISTINCT br.route_short_name) AS routes "
            "FROM bus_stops bs "
            "JOIN bus_stop_times bst ON bs.stop_id = bst.stop_id "
            "JOIN bus_trips bt ON bst.trip_id = bt.trip_id "
            "JOIN bus_routes br ON bt.route_id = br.route_id "
            "WHERE bs.stop_lat BETWEEN ? AND ? AND bs.stop_lon BETWEEN ? AND ? "
            "GROUP BY bs.stop_id "
            "LIMIT ?",
            [south, north, west, east, limit]
        ).fetchall()

        results = []
        for r in rows:
            d = row_to_dict(r)
            if d.get("routes"):
                d["routes"] = d["routes"].split(",")
            else:
                d["routes"] = []
            results.append(d)
        return self._json_response(200, results)

    # ===================================================================
    # GEOCODE
    # ===================================================================

    def _geocode(self, p):
        """Search places, POIs, transit stations, bus stops, and addresses."""
        osm = get_db("osm")
        translink = get_db("transit")
        addr_db = get_db("addresses")
        q = p.get("q", "").strip()
        if not q:
            return self._json_response(400, {"error": "q required"})

        results = []
        seen = set()

        def add_result(d, result_type):
            key = (d.get("name", "").lower(), round(d.get("lat", 0), 4), round(d.get("lon", 0), 4))
            if key not in seen:
                seen.add(key)
                d["result_type"] = result_type
                results.append(d)

        q_upper = q.upper()
        q_lower = q.lower()

        # -- 1. OSM places (cities, towns, villages) --
        if osm:
            row = osm.execute(
                """SELECT name, lat, lon, place_type FROM places WHERE LOWER(name) = LOWER(?)
                   ORDER BY
                     CASE WHEN lat BETWEEN 48.0 AND 60.0 AND lon BETWEEN -140.0 AND -114.0 THEN 0 ELSE 1 END,
                     CASE WHEN lat BETWEEN 42.0 AND 84.0 AND lon BETWEEN -141.0 AND -52.0 THEN 0 ELSE 1 END,
                     CASE place_type WHEN 'city' THEN 0 WHEN 'town' THEN 1 WHEN 'village' THEN 2
                          WHEN 'suburb' THEN 3 WHEN 'neighbourhood' THEN 4 WHEN 'hamlet' THEN 5 ELSE 6 END
                   LIMIT 1""",
                (q,),
            ).fetchall()
            if not row:
                row = osm.execute(
                    """SELECT name, lat, lon, place_type FROM places WHERE LOWER(name) LIKE ?
                       ORDER BY
                         CASE WHEN lat BETWEEN 48.0 AND 60.0 AND lon BETWEEN -140.0 AND -114.0 THEN 0 ELSE 1 END,
                         CASE place_type WHEN 'city' THEN 0 WHEN 'town' THEN 1 WHEN 'village' THEN 2 ELSE 3 END,
                         LENGTH(name)
                       LIMIT 1""",
                    (q_lower + "%",),
                ).fetchall()
            if not row:
                row = osm.execute(
                    """SELECT name, lat, lon, place_type FROM places WHERE LOWER(name) LIKE ?
                       ORDER BY
                         CASE WHEN lat BETWEEN 48.0 AND 60.0 AND lon BETWEEN -140.0 AND -114.0 THEN 0 ELSE 1 END,
                         LENGTH(name)
                       LIMIT 1""",
                    ("%" + q_lower + "%",),
                ).fetchall()
            for r in row:
                add_result(row_to_dict(r), "place")

        # -- 2. OSM POIs (restaurants, parks, hospitals, shops) --
        if osm and len(results) < 10:
            poi_rows = osm.execute(
                """SELECT name, lat, lon, type, subtype, address
                   FROM pois
                   WHERE LOWER(name) = LOWER(?)
                     AND lat BETWEEN 48.0 AND 60.0 AND lon BETWEEN -140.0 AND -114.0
                   ORDER BY LENGTH(name)
                   LIMIT 1""",
                (q,),
            ).fetchall()
            if not poi_rows:
                poi_rows = osm.execute(
                    """SELECT name, lat, lon, type, subtype, address
                       FROM pois
                       WHERE LOWER(name) LIKE ?
                         AND lat BETWEEN 48.0 AND 60.0 AND lon BETWEEN -140.0 AND -114.0
                       ORDER BY LENGTH(name)
                       LIMIT 1""",
                    (q_lower + "%",),
                ).fetchall()
            if not poi_rows:
                poi_rows = osm.execute(
                    """SELECT name, lat, lon, type, subtype, address
                       FROM pois
                       WHERE LOWER(name) LIKE ?
                         AND lat BETWEEN 48.0 AND 60.0 AND lon BETWEEN -140.0 AND -114.0
                       ORDER BY LENGTH(name)
                       LIMIT 1""",
                    ("%" + q_lower + "%",),
                ).fetchall()
            for r in poi_rows:
                d = row_to_dict(r)
                poi_type = d.get("subtype") or d.get("type") or ""
                if poi_type and poi_type not in ("yes", "no"):
                    d["poi_type"] = poi_type
                add_result(d, "poi")

        # -- 3. Transit stations (SkyTrain/SeaBus) --
        if translink and len(results) < 10:
            stn_rows = translink.execute(
                """SELECT DISTINCT
                     REPLACE(REPLACE(REPLACE(stop_name, ' @ Platform 1', ''),
                                      ' @ Platform 2', ''),
                             ' @ Platform 3', '') as name,
                     lat, lon,
                     GROUP_CONCAT(DISTINCT l.route_name) as lines
                   FROM stations s
                   LEFT JOIN station_lines sl ON s.stop_id = sl.stop_id
                   LEFT JOIN lines l ON sl.route_id = l.route_id
                   WHERE s.stop_name LIKE ?
                   GROUP BY name, lat, lon
                   ORDER BY LENGTH(name), name
                   LIMIT 1""",
                ("%" + q_upper + "%",),
            ).fetchall()
            for r in stn_rows:
                d = row_to_dict(r)
                d["place_type"] = "station"
                add_result(d, "station")

        # -- 4. Bus stops --
        if translink and len(results) < 10:
            bus_rows = translink.execute(
                """SELECT stop_name AS name, stop_lat AS lat, stop_lon AS lon
                   FROM bus_stops
                   WHERE stop_name LIKE ?
                   ORDER BY LENGTH(stop_name)
                   LIMIT 1""",
                ("%" + q_upper + "%",),
            ).fetchall()
            for r in bus_rows:
                d = row_to_dict(r)
                d["place_type"] = "bus_stop"
                add_result(d, "bus_stop")

        # -- 5. Addresses --
        if addr_db and len(results) < 10:
            max_addr = min(4, 10 - len(results))
            addr_rows = addr_db.execute(
                """SELECT lat, lon,
                     CASE WHEN street_no IS NOT NULL AND street_no != ''
                       THEN street_no || ' ' || street_name || ' ' || COALESCE(street_type,'')
                       ELSE full_addr
                     END AS display_name,
                     city, postal_code, 'address' AS place_type
                   FROM addresses
                   WHERE province = 'BC' AND street_name LIKE ?
                   ORDER BY LENGTH(full_addr)
                   LIMIT ?""",
                (q_upper + "%", max_addr),
            ).fetchall()
            if not addr_rows:
                addr_rows = addr_db.execute(
                    """SELECT lat, lon,
                        CASE WHEN street_no IS NOT NULL AND street_no != ''
                          THEN street_no || ' ' || street_name || ' ' || COALESCE(street_type,'')
                          ELSE full_addr
                        END AS display_name,
                        city, postal_code, 'address' AS place_type
                       FROM addresses
                       WHERE province = 'BC' AND street_name LIKE ?
                       ORDER BY LENGTH(full_addr)
                       LIMIT ?""",
                    ("%" + q_upper + "%", max_addr),
                ).fetchall()
            if not addr_rows:
                addr_rows = addr_db.execute(
                    """SELECT lat, lon, full_addr AS display_name,
                       city, postal_code, 'address' AS place_type
                       FROM addresses
                       WHERE province = 'BC' AND full_addr LIKE ?
                       ORDER BY LENGTH(full_addr)
                       LIMIT ?""",
                    ("%" + q_upper + "%", max_addr),
                ).fetchall()
            for r in addr_rows:
                d = row_to_dict(r)
                d["name"] = d.get("display_name", d.get("name", ""))
                add_result(d, "address")

        # -- 6. Natural features (peaks, lakes, bays, capes) --
        if osm and len(results) < 10:
            nat_rows = osm.execute(
                """SELECT name, feature_type AS place_type, lat, lon
                   FROM natural_features
                   WHERE LOWER(name) LIKE ?
                     AND lat BETWEEN 48.0 AND 60.0 AND lon BETWEEN -140.0 AND -114.0
                   ORDER BY LENGTH(name)
                   LIMIT 1""",
                ("%" + q_lower + "%",),
            ).fetchall()
            for r in nat_rows:
                add_result(row_to_dict(r), "natural")

        # -- 7. Trail groups --
        trail_db = get_db("trails")
        if trail_db and len(results) < 10:
            trail_rows = trail_db.execute(
                """SELECT name, lat, lon, total_length_km, segment_count, trail_type
                   FROM trail_groups
                   WHERE LOWER(name) LIKE ?
                     AND lat BETWEEN 48.0 AND 60.0 AND lon BETWEEN -140.0 AND -114.0
                   ORDER BY LENGTH(name)
                   LIMIT 1""",
                ("%" + q_lower + "%",),
            ).fetchall()
            for r in trail_rows:
                d = row_to_dict(r)
                d["place_type"] = "trail"
                add_result(d, "trail")

        return self._json_response(200, results)
    def _location_update(self):
        global _last_location
        data = self._read_body()
        with _location_lock:
            _last_location = {
                "lat": data.get("lat"),
                "lon": data.get("lon"),
                "accuracy": data.get("accuracy"),
                "timestamp": datetime.utcnow().isoformat(),
            }
        return self._json_response(200, {"ok": True})

    def _location_get(self, p):
        with _location_lock:
            return self._json_response(200, dict(_last_location))

