    def _elevation(self, params):
        """Query elevation at a point. Params: lat, lon"""
        lat = float(params.get('lat', 0))
        lon = float(params.get('lon', 0))
        result = self._query_elevation(lat, lon)
        if result is None:
            return self._json_response(404, {"error": "no elevation data for this location"})
        return self._json_response(200, {"lat": lat, "lon": lon, "elevation_m": result})

    def _elevation_profile(self, params):
        """Elevation profile between two points. Params: lat1,lon1,lat2,lon2,points"""
        import zlib, struct

        lat1 = float(params.get('lat1', 0))
        lon1 = float(params.get('lon1', 0))
        lat2 = float(params.get('lat2', 0))
        lon2 = float(params.get('lon2', 0))
        n = int(params.get('points', 50))
        n = max(2, min(200, n))

        # Per-tile cache: tile_name -> (n_rows, n_cols, min_lat, max_lat, min_lon, max_lon, values)
        tile_cache = {}

        def get_elevation(lat, lon):
            for key in ['elevation', 'elevation_ukraine']:
                elev_db = DB_PATHS.get(key)
                if not elev_db or not os.path.exists(elev_db):
                    continue

                # Find tiles covering this point (from cache or DB)
                db_key = f'{key}:{elev_db}'
                if db_key not in tile_cache:
                    tile_cache[db_key] = {'conn': sqlite3.connect(elev_db), 'tiles': {}}

                conn_info = tile_cache[db_key]
                conn = conn_info['conn']

                # Check cached tiles first
                for cached in conn_info['tiles'].values():
                    if cached['min_lat'] <= lat <= cached['max_lat'] and cached['min_lon'] <= lon <= cached['max_lon']:
                        return _sample_tile(cached, lat, lon)

                # Query DB for tiles covering this point
                c = conn.cursor()
                c.execute('''
                    SELECT tile_name, data, grid_rows, grid_cols, min_lat, max_lat, min_lon, max_lon
                    FROM elevation_grid
                    WHERE min_lat <= ? AND max_lat >= ? AND min_lon <= ? AND max_lon >= ?
                ''', (lat, lat, lon, lon))
                rows = c.fetchall()

                for row in rows:
                    tile_name = row[0]
                    if tile_name in conn_info['tiles']:
                        cached = conn_info['tiles'][tile_name]
                        if cached['min_lat'] <= lat <= cached['max_lat'] and cached['min_lon'] <= lon <= cached['max_lon']:
                            return _sample_tile(cached, lat, lon)
                        continue

                    # Decode and cache
                    compressed = row[1]
                    binary = zlib.decompress(compressed)
                    values = struct.unpack(f'>{len(binary)//2}h', binary)
                    cached = {
                        'n_rows': row[2], 'n_cols': row[3],
                        'min_lat': row[4], 'max_lat': row[5],
                        'min_lon': row[6], 'max_lon': row[7],
                        'values': values
                    }
                    conn_info['tiles'][tile_name] = cached
                    return _sample_tile(cached, lat, lon)

            return None

        def _sample_tile(cached, lat, lon):
            n_rows, n_cols = cached['n_rows'], cached['n_cols']
            t_min_lat, t_max_lat = cached['min_lat'], cached['max_lat']
            t_min_lon, t_max_lon = cached['min_lon'], cached['max_lon']
            values = cached['values']

            row_frac = (t_max_lat - lat) / (t_max_lat - t_min_lat)
            col_frac = (lon - t_min_lon) / (t_max_lon - t_min_lon)
            row_frac = max(0.0, min(1.0, row_frac))
            col_frac = max(0.0, min(1.0, col_frac))

            ci = min(int(col_frac * (n_cols - 1)), n_cols - 1)
            ri = n_rows - 1 - min(int(row_frac * (n_rows - 1)), n_rows - 1)
            idx = ci * n_rows + ri

            if idx < len(values):
                val = values[idx]
                if val > -32000 and val < 32000:
                    return val
            return None

        # Query all sample points
        points = []
        for i in range(n):
            t = i / (n - 1)
            lat = lat1 + t * (lat2 - lat1)
            lon = lon1 + t * (lon2 - lon1)
            elev = get_elevation(lat, lon)
            points.append({"lat": round(lat, 5), "lon": round(lon, 5), "elevation_m": elev})

        # Cleanup connections
        for info in tile_cache.values():
            info['conn'].close()

        elevations = [p["elevation_m"] for p in points if p["elevation_m"] is not None]
        gain = sum(max(0, elevations[i] - elevations[i-1]) for i in range(1, len(elevations)))
        loss = sum(abs(min(0, elevations[i] - elevations[i-1])) for i in range(1, len(elevations)))

        return self._json_response(200, {
            "points": points,
            "elevation_gain_m": round(gain),
            "elevation_loss_m": round(loss),
            "elevation_min_m": min(elevations) if elevations else None,
            "elevation_max_m": max(elevations) if elevations else None,
        })

    def _weather(self, params):
        """Weather forecast from Open-Meteo."""
        lat = _float(params.get('lat'))
        lon = _float(params.get('lon'))
        if lat is None or lon is None:
            return self._json_response(400, {'error': 'lat and lon required'})

        cache_key = f'{lat:.2f},{lon:.2f}'
        now = time.time()
        with _weather_cache_lock:
            cached = _weather_cache.get(cache_key)
            if cached and now - cached['timestamp'] < 600:  # 10 minutes
                return self._json_response(200, cached['data'])

        # Fetch from Open-Meteo
        url = f'https://api.open-meteo.com/v1/forecast?latitude={lat}&longitude={lon}&current=temperature_2m,relative_humidity_2m,wind_speed_10m,weather_code&hourly=temperature_2m,weather_code&timezone=auto&forecast_days=2'
        try:
            req = urllib.request.Request(url, headers={'User-Agent': 'GeoDashboard/1.0'})
            with urllib.request.urlopen(req) as resp:
                data = json.loads(resp.read().decode())
        except Exception as e:
            return self._json_response(500, {'error': f'Failed to fetch weather: {e}'})

        # Map weather codes to icons and descriptions
        wmo_codes = {
            0: ('☀️', 'Clear'), 1: ('🌤️', 'Mainly clear'), 2: ('⛅', 'Partly cloudy'),
            3: ('☁️', 'Overcast'), 45: ('🌫️', 'Fog'), 48: ('🌫️', 'Depositing rime fog'),
            51: ('🌦️', 'Light drizzle'), 53: ('🌦️', 'Moderate drizzle'), 55: ('🌦️', 'Dense drizzle'),
            56: ('🌧️', 'Light freezing drizzle'), 57: ('🌧️', 'Dense freezing drizzle'),
            61: ('🌧️', 'Slight rain'), 63: ('🌧️', 'Moderate rain'), 65: ('🌧️', 'Heavy rain'),
            66: ('🌧️', 'Light freezing rain'), 67: ('🌧️', 'Heavy freezing rain'),
            71: ('🌨️', 'Slight snow'), 73: ('🌨️', 'Moderate snow'), 75: ('🌨️', 'Heavy snow'),
            77: ('🌨️', 'Snow grains'), 80: ('🌧️', 'Slight rain showers'),
            81: ('🌧️', 'Moderate rain showers'), 82: ('🌧️', 'Violent rain showers'),
            85: ('🌨️', 'Slight snow showers'), 86: ('🌨️', 'Heavy snow showers'),
            95: ('⛈️', 'Thunderstorm'), 96: ('⛈️', 'Thunderstorm with slight hail'),
            99: ('⛈️', 'Thunderstorm with heavy hail'),
        }

        current = data.get('current', {})
        hourly = data.get('hourly', {})

        # Current weather
        weather_code = current.get('weather_code', 0)
        icon, desc = wmo_codes.get(weather_code, ('❓', 'Unknown'))
        current_weather = {
            'temperature': current.get('temperature_2m'),
            'humidity': current.get('relative_humidity_2m'),
            'wind_speed': current.get('wind_speed_10m'),
            'weather_code': weather_code,
            'icon': icon,
            'description': desc,
        }

        # Hourly forecast (next 24h)
        times = hourly.get('time', [])
        temps = hourly.get('temperature_2m', [])
        codes = hourly.get('weather_code', [])
        hourly_forecast = []
        now_timestamp = time.time()
        for i, (t, temp, code) in enumerate(zip(times, temps, codes)):
            # Convert ISO string to timestamp
            # Simple filtering: only future hours, up to 24
            if i >= 24:
                break
            icon_h, desc_h = wmo_codes.get(code, ('❓', 'Unknown'))
            hourly_forecast.append({
                'time': t,
                'temperature': temp,
                'weather_code': code,
                'icon': icon_h,
                'description': desc_h,
            })

        result = {
            'current': current_weather,
            'hourly': hourly_forecast,
            'units': {
                'temperature': '°C',
                'humidity': '%',
                'wind_speed': 'km/h',
            },
            'cached': False,
        }

        with _weather_cache_lock:
            _weather_cache[cache_key] = {'timestamp': now, 'data': result}

        return self._json_response(200, result)

    def _ferries(self, params):
        """Return BC Ferries routes and terminal locations."""
        # Cache for 5 minutes
        cache_key = 'routes'
        now = time.time()
        with _ferries_cache_lock:
            cached = _ferries_cache.get(cache_key)
            if cached and now - cached['timestamp'] < 300:
                return self._json_response(200, cached['data'])

        # Fetch from bcferriesapi.ca
        url = 'https://www.bcferriesapi.ca/v2/'
        try:
            req = urllib.request.Request(url, headers={'User-Agent': 'GeoDashboard/1.0'})
            with urllib.request.urlopen(req) as resp:
                data = json.loads(resp.read().decode())
        except Exception as e:
            return self._json_response(500, {'error': f'Failed to fetch ferries data: {e}'})

        # Merge capacity and non-capacity routes, deduplicate
        capacity = data.get('capacityRoutes', [])
        noncapacity = data.get('nonCapacityRoutes', [])
        all_routes = {}
        for route in capacity + noncapacity:
            code = route.get('routeCode')
            if code not in all_routes:
                all_routes[code] = route

        # Terminal coordinates mapping (from bcferries script)
        terminals = {
            'TSA': {'name': 'Tsawwassen', 'lat': 49.016, 'lon': -123.132},
            'SWB': {'name': 'Swartz Bay', 'lat': 48.781, 'lon': -123.159},
            'HSB': {'name': 'Horseshoe Bay', 'lat': 49.374, 'lon': -123.271},
            'DUK': {'name': 'Duke Point', 'lat': 49.152, 'lon': -123.945},
            'LNG': {'name': 'Langdale', 'lat': 49.434, 'lon': -123.472},
            'NAN': {'name': 'Departure Bay', 'lat': 49.194, 'lon': -123.958},
            'FUL': {'name': 'Fulford Harbour', 'lat': 48.766, 'lon': -123.442},
            'BOW': {'name': 'Bowen Island', 'lat': 49.378, 'lon': -123.336},
            'SGI': {'name': 'Southern Gulf Islands', 'lat': 48.85, 'lon': -123.5},
        }

        # Route mapping with friendly names
        route_names = {
            'TSASWB': 'Tsawwassen → Swartz Bay',
            'TSADUK': 'Tsawwassen → Duke Point',
            'TSASGI': 'Tsawwassen → Southern Gulf Islands',
            'SWBTSA': 'Swartz Bay → Tsawwassen',
            'SWBFUL': 'Swartz Bay → Fulford Harbour',
            'SWBSGI': 'Swartz Bay → Southern Gulf Islands',
            'HSBNAN': 'Horseshoe Bay → Departure Bay',
            'HSBLNG': 'Horseshoe Bay → Langdale',
            'HSBBOW': 'Horseshoe Bay → Bowen Island',
            'NANHSB': 'Departure Bay → Horseshoe Bay',
            'LNGHSB': 'Langdale → Horseshoe Bay',
            'FULSWB': 'Fulford Harbour → Swartz Bay',
            'DUKTSA': 'Duke Point → Tsawwassen',
            'BOWHSB': 'Bowen Island → Horseshoe Bay',
        }

        # Build response
        routes = []
        for code, route in all_routes.items():
            from_code = code[:3]
            to_code = code[3:]
            from_term = terminals.get(from_code, {'name': from_code, 'lat': None, 'lon': None})
            to_term = terminals.get(to_code, {'name': to_code, 'lat': None, 'lon': None})
            routes.append({
                'code': code,
                'name': route_names.get(code, code),
                'from': from_term,
                'to': to_term,
                'sailing_duration': route.get('sailingDuration'),
                'has_capacity': route.get('hasCapacity', False),
            })

        result = {
            'routes': routes,
            'terminals': terminals,
            'cached': False,
        }

        with _ferries_cache_lock:
            _ferries_cache[cache_key] = {'timestamp': now, 'data': result}

        return self._json_response(200, result)

    def _ferries_route_schedule(self, route_code, params):
        """Return schedule for a specific route."""
        # Cache per route for 5 minutes
        cache_key = f'schedule_{route_code}'
        now = time.time()
        with _ferries_cache_lock:
            cached = _ferries_cache.get(cache_key)
            if cached and now - cached['timestamp'] < 300:
                return self._json_response(200, cached['data'])

        # Fetch all routes data (reuse API call)
        url = 'https://www.bcferriesapi.ca/v2/'
        try:
            req = urllib.request.Request(url, headers={'User-Agent': 'GeoDashboard/1.0'})
            with urllib.request.urlopen(req) as resp:
                data = json.loads(resp.read().decode())
        except Exception as e:
            return self._json_response(500, {'error': f'Failed to fetch ferries data: {e}'})

        # Find route
        capacity = data.get('capacityRoutes', [])
        noncapacity = data.get('nonCapacityRoutes', [])
        route = None
        for r in capacity + noncapacity:
            if r.get('routeCode') == route_code:
                route = r
                break
        if not route:
            return self._json_response(404, {'error': f'Route {route_code} not found'})

        # Sailings (filter future ones)
        sailings = route.get('sailings', [])
        future_sailings = []
        for s in sailings:
            status = s.get('sailingStatus')
            if status in ('future', 'current'):
                future_sailings.append({
                    'time': s.get('time'),
                    'arrival_time': s.get('arrivalTime'),
                    'vessel_name': s.get('vesselName'),
                    'fill': s.get('fill'),
                    'car_fill': s.get('carFill'),
                    'status': status,
                })
        # Limit to next 3 sailings
        future_sailings = future_sailings[:3]

        result = {
            'route_code': route_code,
            'sailings': future_sailings,
            'cached': False,
        }

        with _ferries_cache_lock:
            _ferries_cache[cache_key] = {'timestamp': now, 'data': result}

        return self._json_response(200, result)

    def _query_elevation(self, lat, lon):
        """Query elevation at a single point from elevation.db (Canada) and elevation-ukraine.db."""
        import zlib, struct

        db_keys = ['elevation', 'elevation_ukraine']
        all_rows = []

        for key in db_keys:
            elev_db = DB_PATHS.get(key)
            if not elev_db or not os.path.exists(elev_db):
                continue

            conn = sqlite3.connect(elev_db)
            c = conn.cursor()
            c.execute('''
                SELECT data, grid_rows, grid_cols, min_lat, max_lat, min_lon, max_lon
                FROM elevation_grid
                WHERE min_lat <= ? AND max_lat >= ? AND min_lon <= ? AND max_lon >= ?
            ''', (lat, lat, lon, lon))
            rows = c.fetchall()
            conn.close()
            all_rows.extend(rows)

        if not all_rows:
            return None

        # Pick the tile where the point is closest to the tile center
        # This avoids picking wrong tiles at tile boundaries (e.g., mountain vs valley)
        def center_dist(r):
            c_lat = (r[3] + r[4]) / 2
            c_lon = (r[5] + r[6]) / 2
            return (c_lat - lat) ** 2 + (c_lon - lon) ** 2
        all_rows.sort(key=center_dist)

        compressed, n_rows, n_cols, t_min_lat, t_max_lat, t_min_lon, t_max_lon = all_rows[0]
        binary = zlib.decompress(compressed)
        values = struct.unpack(f'>{len(binary)//2}h', binary)

        row_frac = (t_max_lat - lat) / (t_max_lat - t_min_lat)
        col_frac = (lon - t_min_lon) / (t_max_lon - t_min_lon)
        row_frac = max(0.0, min(1.0, row_frac))
        col_frac = max(0.0, min(1.0, col_frac))

        ci = min(int(col_frac * (n_cols - 1)), n_cols - 1)
        # CDED profile data is stored south→north (row 0 = southernmost = min_lat)
        # Our formula gives row_frac=0 at max_lat (northern edge), so we must flip
        ri = n_rows - 1 - min(int(row_frac * (n_rows - 1)), n_rows - 1)
        idx = ci * n_rows + ri

        if idx >= len(values):
            return None
        val = values[idx]
        if val <= -32000 or val >= 32000:
            return None
        return val




