    def _sea_pois(self, params):
        """Return coastal/maritime POIs from local OSM DB."""
        lat = _float(params.get('lat', '49.3'))
        lon = _float(params.get('lon', '-123.3'))
        radius = _float(params.get('radius', '100'))
        ptype = params.get('type', '')
        limit = min(_int(params.get('limit', '200'), 200), 500)

        db = get_db('osm')
        if not db:
            return self._json_response(500, {"error": "OSM database not available"})

        SEAMARK_COL = """json_extract(p.tags, '$."seamark:type"')"""
        AMENITY_COL = "json_extract(p.tags, '$.amenity')"
        MANMADE_COL = "json_extract(p.tags, '$.man_made')"
        NATURAL_COL = "json_extract(p.tags, '$.natural')"
        LEISURE_COL = "json_extract(p.tags, '$.leisure')"

        type_conditions = []
        if not ptype or ptype == 'all':
            type_conditions = [
                f"{SEAMARK_COL} IN ('harbour','small_craft_facility','marina','light_major','coastguard_station','wreck','restricted_area')",
                f"{AMENITY_COL} IN ('marina','ferry_terminal','boat_rental','boat_storage')",
                f"{MANMADE_COL} = 'lighthouse'",
                f"{NATURAL_COL} IN ('beach','cliff','reef')",
                f"{LEISURE_COL} IN ('marina','slipway')",
            ]
        else:
            type_map = {
                'harbour': f"{SEAMARK_COL} = 'harbour'",
                'marina': f"({SEAMARK_COL} IN ('marina','small_craft_facility','harbour') OR {AMENITY_COL} = 'marina' OR {LEISURE_COL} = 'marina')",
                'beach': f"{NATURAL_COL} = 'beach'",
                'lighthouse': f"{MANMADE_COL} = 'lighthouse'",
                'slipway': f"{LEISURE_COL} = 'slipway'",
                'ferry': f"{AMENITY_COL} = 'ferry_terminal'",
                'wreck': f"{SEAMARK_COL} = 'wreck'",
                'anchor': f"{SEAMARK_COL} = 'small_craft_facility'",
                'boat_rental': f"{AMENITY_COL} = 'boat_rental'",
                'cliff': f"{NATURAL_COL} = 'cliff'",
                'coastguard': f"{SEAMARK_COL} = 'coastguard_station'",
            }
            if ptype in type_map:
                type_conditions = [type_map[ptype]]
            else:
                type_conditions = ["1=0"]

        type_where = '(' + ' OR '.join(type_conditions) + ')'
        dist_sql = haversine_sql('p.lat', 'p.lon', lat, lon)

        query = f"""
            SELECT p.*, {dist_sql} as dist
            FROM pois p
            WHERE {type_where}
              AND p.lon != 0 AND p.lat != 0
              AND p.lat IS NOT NULL AND p.lon IS NOT NULL
              AND {dist_sql} <= ?
            ORDER BY dist
            LIMIT ?
        """

        try:
            cur = db.execute(query, (radius * 1000, limit))
            results = []
            for row in cur.fetchall():
                tags = json.loads(row['tags']) if isinstance(row['tags'], str) else (row['tags'] or {})
                poi_type = (tags.get('seamark:type') or tags.get('amenity') or
                           tags.get('man_made') or tags.get('leisure') or
                           tags.get('natural') or 'unknown')
                poi = {
                    'id': row['id'],
                    'name': row['name'] or tags.get('seamark:name', ''),
                    'lat': row['lat'],
                    'lon': row['lon'],
                    'type': poi_type,
                    'dist_km': round(row['dist'] / 1000, 1),
                }
                for k in ['website', 'phone', 'operator', 'capacity', 'toilets',
                          'internet_access', 'fuel', 'description', 'wikidata',
                          'wikipedia', 'image', 'maxlength', 'depth',
                          'seamark:name', 'opening_hours']:
                    if k in tags:
                        poi[k] = tags[k]
                results.append(poi)

            return self._json_response(200, {"count": len(results), "pois": results})
        except Exception as e:
            return self._json_response(500, {"error": str(e)})

