    def _sea_trails(self, params):
        """Return coastal/waterfront trails from trails DB."""
        db = get_db('trails')
        if not db:
            return self._json_response(500, {"error": "Trails database not available"})

        lat = _float(params.get('lat', '49.3'))
        lon = _float(params.get('lon', '-123.3'))
        radius = _float(params.get('radius', '100'))
        limit = min(_int(params.get('limit', '50'), 50), 200)

        # Use REGEXP for faster single-pass match instead of 22 LIKE clauses
        coastal_pattern = 'coast|sea|ocean|beach|shore|waterfront|marine|bay|harbour|harbor|cove|headland|lighthouse|peninsula|island|cape|strait|tidal|wharf|pier|seawall'
        dist_sql = haversine_sql('lat', 'lon', lat, lon)

        # Fallback to LIKE if REGEXP not available
        try:
            db.execute("SELECT 1 WHERE 'test' REGEXP 't'")
            has_regexp = True
        except Exception:
            has_regexp = False

        if has_regexp:
            where = f"LOWER(name) REGEXP '{coastal_pattern}'"
        else:
            coastal_kw = coastal_pattern.split('|')
            where = ' OR '.join([f"LOWER(name) LIKE '%{kw}%'" for kw in coastal_kw])

        cur = db.execute(f"""
            SELECT *, {dist_sql} as dist
            FROM trail_groups
            WHERE ({where})
              AND {dist_sql} <= ?
            ORDER BY dist
            LIMIT ?
        """, (radius * 1000, limit))

        results = []
        for row in cur.fetchall():
            results.append({
                'id': row['id'],
                'name': row['name'],
                'lat': row['lat'],
                'lon': row['lon'],
                'dist_km': round(row['dist'] / 1000, 1),
                'distance_km': row['total_length_km'],
                'difficulty': row['sac_scale'] or '',
                'trail_count': row['segment_count'],
            })

        return self._json_response(200, {"count": len(results), "trails": results})


