    def _serve_static(self, path):
        """Serve static files from STATIC_DIR (or ROADS_STATIC_DIR for roads.ogsapps.cc)."""
        # Host-based routing: serve roads content for roads.ogsapps.cc
        host = self.headers.get('Host', '').lower()
        if 'roads.ogsapps.cc' in host:
            base_dir = ROADS_STATIC_DIR
        else:
            base_dir = STATIC_DIR

        # Map / to index.html
        if path == '/' or path == '':
            filename = 'index.html'
        else:
            # Strip leading slash
            filename = path.lstrip('/')

        # Security: reject paths with directory traversal
        filepath = os.path.normpath(os.path.join(base_dir, filename))
        if not filepath.startswith(os.path.normpath(base_dir)):
            return self._json_response(403, {"error": "forbidden"})

        if not os.path.isfile(filepath):
            return self._json_response(404, {"error": "not found"})

        # Determine content type
        _, ext = os.path.splitext(filename)
        content_type = self._MIME_TYPES.get(ext, 'application/octet-stream')

        try:
            with open(filepath, 'rb') as f:
                body = f.read()
            self.send_response(200)
            self.send_header('Content-Type', content_type)
            self._send_cors()
            self.send_header('Content-Length', str(len(body)))
            self.end_headers()
            self.wfile.write(body)
        except IOError:
            self._json_response(500, {"error": "read error"})

    def _proxy_to_ogs_api(self, path, params):
        """Proxy request to ogs-api on localhost:8091."""
        qs = urllib.parse.urlencode(params)
        url = f'http://localhost:8091{path}'
        if qs:
            url += '?' + qs
        try:
            req = urllib.request.Request(url, headers={'User-Agent': 'ogsapps-geo/1.0'})
            with urllib.request.urlopen(req, timeout=12) as resp:
                data = resp.read()
            self.send_response(200)
            self.send_header('Content-Type', 'application/json')
            self.send_header('Content-Length', str(len(data)))
            self.send_header('Access-Control-Allow-Origin', '*')
            self.send_header('Cache-Control', 'public, max-age=300')
            self.end_headers()
            self.wfile.write(data)
        except urllib.error.URLError:
            self._json_response(200, {'breaking': [], 'error': 'ogs-api unavailable'})
        except Exception as e:
            self._json_response(200, {'breaking': [], 'error': str(e)})

    # ── Roads Events (DriveBC Open511) ────────────────────────

    _roads_cache = {}
    _roads_cache_lock = threading.Lock()

    def _roads_events(self, params):
        """Proxy DriveBC Open511 API for road events. Cached."""
        import threading
        cache_key = "all"
        # Optional area filter
        area = params.get('area', '').strip()
        severity = params.get('severity', '').strip()
        event_type = params.get('type', '').strip()
        if area:
            cache_key += f"_area={area}"
        if severity:
            cache_key += f"_sev={severity}"
        if event_type:
            cache_key += f"_type={event_type}"

        now = time.time()
        with self._roads_cache_lock:
            cached = self._roads_cache.get(cache_key)
            if cached and now - cached['ts'] < 120:
                data = cached['data']
                self.send_response(200)
                self.send_header('Content-Type', 'application/json')
                self._send_cors()
                self.send_header('Cache-Control', 'public, max-age=120')
                self.send_header('Content-Length', str(len(data)))
                self.end_headers()
                self.wfile.write(data)
                return

        # Build Open511 URL
        url = "https://api.open511.gov.bc.ca/events?limit=200"
        if area:
            url += f"&area_id=drivebc.ca/{area}"
        if severity:
            url += f"&severity={severity}"
        if event_type:
            url += f"&event_type={event_type}"

        try:
            req = urllib.request.Request(url, headers={'User-Agent': 'ogsapps-roads/1.0', 'Accept': 'application/json'})
            with urllib.request.urlopen(req, timeout=15) as resp:
                raw = resp.read().decode()
            data = raw.encode()

            with self._roads_cache_lock:
                self._roads_cache[cache_key] = {'ts': now, 'data': data}

            self.send_response(200)
            self.send_header('Content-Type', 'application/json')
            self._send_cors()
            self.send_header('Cache-Control', 'public, max-age=120')
            self.send_header('Content-Length', str(len(data)))
            self.end_headers()
            self.wfile.write(data)
        except urllib.error.HTTPError as e:
            self._json_response(e.code, {"error": f"DriveBC API error: {e.code}", "events": []})
        except urllib.error.URLError as e:
            self._json_response(502, {"error": f"DriveBC API unreachable: {e.reason}", "events": []})
        except Exception as e:
            self._json_response(500, {"error": str(e), "events": []})

    # ── Roads Routing (OSRM proxy) ──────────────────────────

    def _roads_route(self, params):
        """Proxy driving directions to OSRM demo server. Accepts from=lon,lat&to=lon,lat"""
        from_coord = (params.get('from') or '').strip()
        to_coord = (params.get('to') or '').strip()

        if not from_coord or not to_coord:
            return self._json_response(400, {"error": "Missing from/to coordinates. Use from=lon,lat&to=lon,lat"})

        # Validate coordinate format (after URL decoding)
        for name, val in [('from', from_coord), ('to', to_coord)]:
            parts = val.split(',')
            if len(parts) != 2:
                return self._json_response(400, {"error": f"Invalid {name} format. Expected lon,lat"})
            try:
                float(parts[0])
                float(parts[1])
            except ValueError:
                return self._json_response(400, {"error": f"Invalid {name} coordinates. Must be numbers"})

        # Proxy to OSRM demo (lon,lat format)
        osrm_url = f"http://host.containers.internal:5000/route/v1/driving/{from_coord};{to_coord}?overview=full&geometries=geojson&steps=true&annotations=true"
        try:
            req = urllib.request.Request(osrm_url, headers={'User-Agent': 'ogsapps-roads/1.0'})
            with urllib.request.urlopen(req, timeout=15) as resp:
                raw = resp.read().decode()
            data = json.loads(raw)

            if data.get('code') != 'Ok' or not data.get('routes'):
                return self._json_response(404, {"error": "No route found", "osrm_code": data.get('code', 'unknown')})

            route = data['routes'][0]
            result = {
                'distance_km': round(route.get('distance', 0) / 1000, 2),
                'duration_min': round(route.get('duration', 0) / 60, 0),
                'geometry': route.get('geometry'),  # GeoJSON LineString
                'steps': [],
            }
            for step in route.get('legs', [{}])[0].get('steps', []):
                result['steps'].append({
                    'distance_km': round(step.get('distance', 0) / 1000, 2),
                    'duration_min': round(step.get('duration', 0) / 60, 1),
                    'instruction': step.get('name', 'Continue'),
                    'maneuver': step.get('maneuver', {}),
                })

            # ── Elevation profile along route ──
            if result.get('geometry') and result['geometry'].get('coordinates'):
                coords = result['geometry']['coordinates']
                n = min(30, max(2, len(coords)))
                if n >= 2:
                    # Compute cumulative distances along the polyline
                    cumdist = [0.0]
                    for i in range(1, len(coords)):
                        dx = coords[i][0] - coords[i-1][0]
                        dy = coords[i][1] - coords[i-1][1]
                        cumdist.append(cumdist[-1] + math.sqrt(dx*dx + dy*dy))
                    total_dist = cumdist[-1]
                    if total_dist > 0:
                        # Sample n evenly-spaced points
                        sampled = []
                        for j in range(n):
                            target = (j / (n - 1)) * total_dist
                            # Find the two surrounding coordinates
                            k = 0
                            while k < len(cumdist) - 1 and cumdist[k + 1] < target:
                                k += 1
                            if k >= len(coords) - 1:
                                pt = coords[-1]
                            else:
                                seg_dist = cumdist[k+1] - cumdist[k]
                                t = (target - cumdist[k]) / seg_dist if seg_dist > 0 else 0
                                pt = [
                                    coords[k][0] + t * (coords[k+1][0] - coords[k][0]),
                                    coords[k][1] + t * (coords[k+1][1] - coords[k][1]),
                                ]
                            # Query elevation (lon, lat order)
                            elev = self._query_elevation(pt[1], pt[0])
                            sampled.append({
                                'lon': round(pt[0], 5),
                                'lat': round(pt[1], 5),
                                'elevation_m': round(elev, 1) if elev is not None else None,
                                'dist_km': round(target * 111.32, 2),  # approx
                            })
                        # Calculate stats
                        valid = [s['elevation_m'] for s in sampled if s['elevation_m'] is not None]
                        if valid:
                            gain = sum(max(0, valid[i] - valid[i-1]) for i in range(1, len(valid)))
                            loss = sum(abs(min(0, valid[i] - valid[i-1])) for i in range(1, len(valid)))
                            result['elevation'] = {
                                'gain_m': round(gain),
                                'loss_m': round(loss),
                                'min_m': min(valid),
                                'max_m': max(valid),
                                'points': sampled,
                            }

            self._json_response(200, result)
        except urllib.error.URLError:
            self._json_response(502, {"error": "Routing service unavailable"})
        except json.JSONDecodeError:
            self._json_response(502, {"error": "Invalid routing response"})
        except Exception as e:
            self._json_response(500, {"error": str(e)})

