    def _cycling_routes(self, params):
        """Cycling routes near a lat/lon point."""
        lat = _float(params.get('lat'))
        lon = _float(params.get('lon'))
        radius = _float(params.get('radius', '2')) or 2  # km
        canbics = params.get('class', '').strip()
        muni = params.get('municipality', '').strip()
        limit = min(int(params.get('limit', '100')), 500)

        if lat is None or lon is None:
            return self._json_response(400, {'error': 'lat and lon required'})

        # Approx degree offsets (WGS84, simple cos correction)
        dlat = radius / 111.0
        dlon = radius / (111.0 * math.cos(math.radians(lat)))

        db = self._cycling_db()
        try:
            wheres = [f"lat >= {lat - dlat}", f"lat <= {lat + dlat}",
                     f"lon >= {lon - dlon}", f"lon <= {lon + dlon}"]
            if canbics:
                wheres.append(f"canbics_class = '{canbics}'")
            if muni:
                wheres.append(f"municipality = '{muni}'")
            where = ' AND '.join(wheres)
            cur = db.execute(f'''
                SELECT cs.id, cs.municipality, cs.canbics_class, cs.source_class, cs.surface_type,
                       cs.length_km, cs.geometry_json, cs.elevation_json,
                       ce.elevation_gain_m, ce.elevation_min_m, ce.elevation_max_m, ce.difficulty
                FROM cycling_segments cs
