    def _cycling_paths(self, params):
        """Merged cycling paths (cross-class routes)."""
        south = _float(params.get('south'))
        north = _float(params.get('north'))
        west = _float(params.get('west'))
        east = _float(params.get('east'))
        muni = params.get('municipality', '').strip()
        limit = min(int(params.get('limit', '500')), 2000)

        if any(v is None for v in [south, north, west, east]):
            return self._json_response(400, {'error': 'south, north, west, east required'})

        db = self._cycling_db()
        try:
            where_parts = [
                f"max_lat >= {south}",
                f"min_lat <= {north}",
                f"max_lon >= {west}",
                f"min_lon <= {east}",
            ]
            if muni:
                safe_muni = muni.replace("'", "''")
                where_parts.append(f"municipality = '{safe_muni}'")
            where = ' AND '.join(where_parts)
            cur = db.execute(f'''
                SELECT id, segment_count, total_length_km, total_points,
                       dominant_class, class_composition, class_sequence,
                       municipality, geometry_json
                FROM cycling_paths
                WHERE {where} LIMIT {limit}
            ''')
            features = []
            for row in cur:
                geom = json.loads(row[8])
                comp = json.loads(row[5]) if row[5] else {}
                seq = json.loads(row[6]) if row[6] else []
                features.append({
                    'type': 'Feature',
                    'geometry': geom,
                    'properties': {
                        'path_id': row[0],
                        'segment_count': row[1],
                        'total_length_km': row[2],
                        'total_points': row[3],
                        'dominant_class': row[4],
                        'class_composition': comp,
                        'class_sequence': seq,
                        'municipality': row[7],
                        'mode': 'routes',
                    },
                })
            self._json_response(200, {
                'type': 'FeatureCollection',
                'features': features,
                'mode': 'routes',
            })
        finally:
            db.close()

    def _cycling_elevation(self, params):
        """Return elevation profile for a specific cycling segment."""
        seg_id = params.get('id', '').strip()
        if not seg_id:
            return self._json_response(400, {'error': 'id required'})
        db = self._cycling_db()
        try:
            cur = db.execute(
                'SELECT elevation_json FROM cycling_segments WHERE id = ?', (seg_id,))
            row = cur.fetchone()
            if not row or not row[0]:
                return self._json_response(404, {'error': 'No elevation data for segment'})
            return self._json_response(200, json.loads(row[0]))
        finally:
            db.close()

    def _cycling_stats(self, params):
        """Cycling infrastructure stats."""
        db = self._cycling_db()
        try:
            cur = db.execute('''
                SELECT municipality, canbics_class, COUNT(*), ROUND(COALESCE(SUM(length_km),0),1)
                FROM cycling_segments
                GROUP BY municipality, canbics_class ORDER BY municipality, canbics_class
            ''')
            municipalities = {}
            for row in cur:
                muni = row[0]
                if muni not in municipalities:
                    municipalities[muni] = {'classes': {}, 'total_km': 0, 'total_segments': 0}
                municipalities[muni]['classes'][row[1]] = {'segments': row[2], 'km': row[3]}
                municipalities[muni]['total_km'] += row[3]
                municipalities[muni]['total_segments'] += row[2]
            self._json_response(200, {'municipalities': municipalities})
        finally:
            db.close()

    def _cycling_municipalities(self):
        """List available municipalities."""
        db = self._cycling_db()
        try:
            cur = db.execute('''
                SELECT municipality, COUNT(*), ROUND(COALESCE(SUM(length_km),0),1)
                FROM cycling_segments
                GROUP BY municipality ORDER BY SUM(length_km) DESC
            ''')
            result = [{'name': r[0], 'segments': r[1], 'km': r[2]} for r in cur]
            self._json_response(200, {'municipalities': result})
        finally:
            db.close()

    def _mines_list(self, params):
