    def _mines_near(self, params):
        """Mines near a lat/lon point."""
        lat = _float(params.get('lat'))
        lon = _float(params.get('lon'))
        radius = _float(params.get('radius', '100')) or 100  # km
        limit = min(int(params.get('limit', '50')), 200)

        if lat is None or lon is None:
            return self._json_response(400, {'error': 'lat and lon required'})

        dlat = radius / 111.0
        dlon = radius / (111.0 * math.cos(math.radians(lat)))

        db = sqlite3.connect(DB_PATHS["osm"])
        try:
            cur = db.execute(f'''
                SELECT * FROM mines
                WHERE latitude BETWEEN ? AND ? AND longitude BETWEEN ? AND ?
                LIMIT {limit}
            ''', (lat - dlat, lat + dlat, lon - dlon, lon + dlon))
            cols = [d[0] for d in cur.description]
            features = []
            for row in cur:
                props = dict(zip(cols, row))
                mlat, mlon = props.pop('latitude', None), props.pop('longitude', None)
                if mlat and mlon:
                    dist = math.sqrt(((mlat - lat) * 111) ** 2 + ((mlon - lon) * 111 * math.cos(math.radians(lat))) ** 2)
                    props['distance_km'] = round(dist, 1)
                    features.append({'type': 'Feature',
                        'geometry': {'type': 'Point', 'coordinates': [mlon, mlat]},
                        'properties': props})
            features.sort(key=lambda f: f['properties']['distance_km'])
            self._json_response(200, {'type': 'FeatureCollection', 'features': features,
                'count': len(features)})
        finally:
            db.close()

