    def _transit_route(self, p):
        """Transit routing endpoint — calls bin/transit-route."""
        origin = p.get("from", "").strip()
        dest = p.get("to", "").strip()
        depart = p.get("depart", "").strip()

        if not origin or not dest:
            return self._json_response(400, {"error": "Missing 'from' and/or 'to' parameters"})

        import subprocess
        cmd = [os.path.join(WORKSPACE, "bin", "transit-route"),
               "--from", origin, "--to", dest, "--json"]
        if depart:
            cmd.extend(["--depart", depart])

        try:
            result = subprocess.run(cmd, capture_output=True, text=True, timeout=30,
                                    cwd=WORKSPACE)
            if result.returncode != 0:
                err = result.stderr.strip().split(chr(10))[-1] if result.stderr else "No routes found"
                return self._json_response(404, {"error": err})
            data = json.loads(result.stdout)
            return self._json_response(200, data)
        except subprocess.TimeoutExpired:
            return self._json_response(504, {"error": "Route query timed out"})
        except json.JSONDecodeError:
            return self._json_response(500, {"error": "Invalid route output"})


