def _lambert_inv(easting, northing):
    """Inverse Lambert Conformal Conic (EPSG:3347 Stats Canada Lambert) -> WGS84."""
    import math
    a = 6378137.0
    f = 1 / 298.257222101
    e2 = 2 * f - f * f
    sqrt_e = math.sqrt(e2)
    lat1 = math.radians(49); lat2 = math.radians(77)
    lat0 = math.radians(63.390675); lon0 = math.radians(-91.866386)
    x0 = 6200000.0; y0 = 3000000.0

    def _t(lat):
        sl = math.sin(lat)
        return math.sqrt((1 - sl) / (1 + sl)) * ((1 + sqrt_e * sl) / (1 - sqrt_e * sl)) ** (sqrt_e / 2)

    def _m(lat):
        sl = math.sin(lat)
        return math.cos(lat) / math.sqrt(1 - e2 * sl * sl)

    m1, m2 = _m(lat1), _m(lat2)
    t1, t2, t0 = _t(lat1), _t(lat2), _t(lat0)
    n = (math.log(m1) - math.log(m2)) / (math.log(t1) - math.log(t2))
    F = m1 / (n * t1 ** n)
    rho0 = a * F * t0 ** n

    x, y = easting - x0, northing - y0
    rho = math.copysign(math.sqrt(x * x + (rho0 - y) ** 2), n)
    theta = math.atan2(x, rho0 - y)
    t = (rho / (a * F)) ** (1 / n)
    lon = theta / n + lon0

    lat = math.pi / 2 - 2 * math.atan(t)
    for _ in range(15):
        sl = math.sin(lat)
        lat = math.pi / 2 - 2 * math.atan(t * ((1 - sqrt_e * sl) / (1 + sqrt_e * sl)) ** (sqrt_e / 2))
    return math.degrees(lat), math.degrees(lon)


def _lambert_fwd(lat_deg, lon_deg):
    """Forward WGS84 -> Lambert Conformal Conic (EPSG:3347)."""
    import math
    a = 6378137.0
    f = 1 / 298.257222101
    e2 = 2 * f - f * f
    sqrt_e = math.sqrt(e2)
    lat1 = math.radians(49); lat2 = math.radians(77)
    lat0 = math.radians(63.390675); lon0 = math.radians(-91.866386)
    x0 = 6200000.0; y0 = 3000000.0

    def _t(lat):
        sl = math.sin(lat)
        return math.sqrt((1 - sl) / (1 + sl)) * ((1 + sqrt_e * sl) / (1 - sqrt_e * sl)) ** (sqrt_e / 2)

    def _m(lat):
        sl = math.sin(lat)
        return math.cos(lat) / math.sqrt(1 - e2 * sl * sl)

    m1, m2 = _m(lat1), _m(lat2)
    t1, t2, t0 = _t(lat1), _t(lat2), _t(lat0)
    n = (math.log(m1) - math.log(m2)) / (math.log(t1) - math.log(t2))
    F = m1 / (n * t1 ** n)
    rho0 = a * F * t0 ** n

    lat = math.radians(lat_deg); lon = math.radians(lon_deg)
    t = _t(lat)
    rho = a * F * t ** n
    theta = n * (lon - lon0)
    easting = x0 + rho * math.sin(theta)
    northing = y0 + rho0 - rho * math.cos(theta)
    return easting, northing


def _float(v):
    if v is None:
        return None
    try:
        return float(v)
    except (ValueError, TypeError):
        return None


def _int(v, default=None):
    if v is None:
        return default
    try:
        return int(v)
    except (ValueError, TypeError):
        return default


# ---------------------------------------------------------------------------
# Threaded HTTP server
# ---------------------------------------------------------------------------

class ThreadedHTTPServer(HTTPServer):
    """Handle each request in a new thread."""
    daemon_threads = True
    allow_reuse_address = True

    def process_request(self, request, client_address):
        t = threading.Thread(target=self._handle, args=(request, client_address))
        t.daemon = True
        t.start()

    def _handle(self, request, client_address):
        try:
            self.finish_request(request, client_address)
        except Exception:
            self.handle_error(request, client_address)
        finally:
            self.shutdown_request(request)


